/**
 * IC Markets — cTrader Open API Client
 *
 * Protocol : WebSocket + JSON (port 5036)
 * Docs     : https://help.ctrader.com/open-api/
 *
 * Authentication flow (happens inside authenticate()):
 *   1. ProtoOAApplicationAuthReq  → authenticate the app
 *   2. ProtoOAAccountAuthReq      → authenticate the trading account
 *
 * Key operations:
 *   getCandles()   → ProtoOAGetTrendbarsReq
 *   getAccount()   → ProtoOATraderReq
 *   createOrder()  → ProtoOANewOrderReq  (waits for ExecutionEvent)
 *   closeTrade()   → ProtoOAClosePositionReq
 */

import WebSocket from "ws";
import fs from "fs";
import protobuf from "protobufjs";
import Long from "long";
import { config } from "./config.js";

function logConnectionAlert(message) {
  const entry = JSON.stringify({ timestamp: new Date().toISOString(), type: "connection_alert", message }) + "\n";
  try { fs.appendFileSync("activity.log", entry); } catch {}
}

// ─── Payload type constants (Protobuf version) ──────────────────────────────
const PT = {
  ERROR_RES:           2142,
  HEARTBEAT:             51,
  APP_AUTH_REQ:        2100,
  APP_AUTH_RES:        2101,
  ACCOUNT_AUTH_REQ:    2102,
  ACCOUNT_AUTH_RES:    2103,
  VERSION_REQ:         2104,
  VERSION_RES:         2105,
  NEW_ORDER_REQ:       2106,
  TRADER_REQ:          2121,
  TRADER_RES:          2122,
  EXECUTION_EVENT:     2126,
  SUBSCRIBE_SPOTS_REQ: 2127,
  SUBSCRIBE_SPOTS_RES: 2128,
  SPOT_EVENT:          2131,
  ORDER_ERROR_EVENT:   2132,
  RECONCILE_REQ:       2124,
  RECONCILE_RES:       2125,
  GET_TRENDBARS_REQ:   2137,
  GET_TRENDBARS_RES:   2138,
  CLOSE_POSITION_REQ:  2111,
  AMEND_POSITION_SLTP_REQ: 2110,
  SYMBOLS_LIST_REQ:    2114,
  SYMBOLS_LIST_RES:    2115,
  SYMBOL_BY_ID_REQ:    2116,
  SYMBOL_BY_ID_RES:    2117,
  GET_ACCOUNTS_BY_ACCESS_TOKEN_REQ: 2149,
  GET_ACCOUNTS_BY_ACCESS_TOKEN_RES: 2150,
};

// Map of payloadType → Proto message name (for decoding)
const PT_NAMES = {
  51:   "ProtoHeartbeatEvent",
  2100: "ProtoOAApplicationAuthReq",
  2101: "ProtoOAApplicationAuthRes",
  2102: "ProtoOAAccountAuthReq",
  2103: "ProtoOAAccountAuthRes",
  2104: "ProtoOAVersionReq",
  2105: "ProtoOAVersionRes",
  2106: "ProtoOANewOrderReq",
  2114: "ProtoOASymbolsListReq",
  2115: "ProtoOASymbolsListRes",
  2116: "ProtoOASymbolByIdReq",
  2117: "ProtoOASymbolByIdRes",
  2121: "ProtoOATraderReq",
  2122: "ProtoOATraderRes",
  2124: "ProtoOAReconcileReq",
  2125: "ProtoOAReconcileRes",
  2126: "ProtoOAExecutionEvent",
  2127: "ProtoOASubscribeSpotsReq",
  2128: "ProtoOASubscribeSpotsRes",
  2131: "ProtoOASpotEvent",
  2132: "ProtoOAOrderErrorEvent",
  2137: "ProtoOAGetTrendbarsReq",
  2138: "ProtoOAGetTrendbarsRes",
  2110: "ProtoOAAmendPositionSLTPReq",
  2111: "ProtoOAClosePositionReq",
  2142: "ProtoOAErrorRes",
  2149: "ProtoOAGetAccountListByAccessTokenReq",
  2150: "ProtoOAGetAccountListByAccessTokenRes",
};

// Granularity string → cTrader period integer
const PERIOD = {
  M1: 1, M2: 2, M3: 3, M4: 4, M5: 5,
  M10: 6, M15: 7, M30: 8,
  H1: 9, H4: 10, H12: 11,
  D1: 12, W1: 13, MN1: 14,
};

// Granularity → milliseconds (used for timestamp range calculation)
const PERIOD_MS = {
  M1: 60_000, M5: 300_000, M15: 900_000, M30: 1_800_000,
  H1: 3_600_000, H4: 14_400_000, D1: 86_400_000,
};

export class ICMarketsClient {
  constructor() {
    this.ws              = null;
    this.connected       = false;
    this.pendingRequests = new Map();   // msgId → { resolve, reject }
    this.eventListeners  = new Map();   // payloadType → [callbacks]
    this.msgCounter      = 1;
    this.heartbeatTimer  = null;
    this.reconnecting    = false;
    this.root            = null;
    this.proto           = null;        // Cache for loaded proto definitions
    this.symbols         = new Map();   // Cache for symbol details
    // Connection health monitoring (Phase 4)
    this.lastMessageTime = Date.now();
    this.healthCheckTimer = null;
    this.onConnectionLost = null;       // Callback for emergency alert
    this.keepaliveTimer  = null;        // GCP idle connection keepalive
  }

  // ─── Connection ────────────────────────────────────────────────────────────

  async _loadProto() {
    if (this.root) return;
    this.root = await protobuf.load([
      "OpenApiCommonMessages.proto",
      "OpenApiCommonModelMessages.proto",
      "OpenApiMessages.proto",
      "OpenApiModelMessages.proto"
    ]);
  }

  async connect() {
    await this._loadProto();
    const host = config.ctraderEnv === "live"
      ? "live.ctraderapi.com"
      : "demo.ctraderapi.com";

    return new Promise((resolve, reject) => {
      let settled = false;
      const connectTimeout = setTimeout(() => {
        if (settled) return;
        settled = true;
        try { this.ws?.terminate(); } catch {}
        reject(new Error(`Timeout connecting to cTrader WebSocket (${host}:5035)`));
      }, 15_000);

      // Protobuf port is 5035
      this.ws = new WebSocket(`wss://${host}:5035`);

      this.ws.on("open", () => {
        if (settled) return;
        settled = true;
        clearTimeout(connectTimeout);
        this.connected = true;
        this.lastMessageTime = Date.now();
        this._startHeartbeat();
        this._startHealthMonitor();
        this._startKeepalive();
        resolve();
      });

      this.ws.on("message", (raw) => {
        this.lastMessageTime = Date.now();
        this._onMessage(raw);
      });

      this.ws.on("error", (err) => {
        if (!this.connected && !settled) {
          settled = true;
          clearTimeout(connectTimeout);
          reject(err);
        }
        console.error("❌ WebSocket error:", err.message);
      });

      this.ws.on("close", () => {
        clearTimeout(connectTimeout);
        const wasConnected = this.connected;
        this.connected = false;
        clearInterval(this.heartbeatTimer);
        clearInterval(this.healthCheckTimer);
        clearInterval(this.keepaliveTimer);
        // Reject all pending requests — socket is dead
        for (const [id, pending] of this.pendingRequests) {
          pending.reject(new Error("WebSocket closed while waiting for response"));
        }
        this.pendingRequests.clear();
        if (wasConnected && !this.reconnecting) this._scheduleReconnect();
      });
    });
  }

  async _scheduleReconnect() {
    this.reconnecting = true;
    console.log("\n⚠️  Connection lost — reconnecting in 5s...");
    await sleep(5000);
    try {
      await this.connect();
      await this.authenticate();
      console.log("✅ Reconnected.\n");
    } catch (err) {
      console.error("Reconnect failed:", err.message);
    } finally {
      this.reconnecting = false;
    }
  }

  // ─── Authentication ────────────────────────────────────────────────────────

  async authenticate() {
    // Step 1: authenticate the application
    await this._send(PT.APP_AUTH_REQ, {
      clientId:     config.ctraderClientId,
      clientSecret: config.ctraderClientSecret,
    });

    // Step 2: authenticate the trading account
    await this._send(PT.ACCOUNT_AUTH_REQ, {
      ctidTraderAccountId: Long.fromValue(config.ctraderAccountId),
      accessToken:         config.ctraderAccessToken,
    });
  }

  // ─── Market Data ───────────────────────────────────────────────────────────

  /**
   * Fetch historical candles and return them in the standard format
   * used by indicators.js (same shape as OANDA/Alpaca candles)
   */
  async getCandles(instrument, granularity = "M5", count = 100, from = null, to = null, quoteType = 1) {
    const symbolId = this._resolveSymbolId(instrument);
    const period   = PERIOD[granularity];
    if (!period) throw new Error(`Unknown granularity: ${granularity}`);

    const periodMs    = PERIOD_MS[granularity] ?? 300_000;
    const toTimestamp = to || Date.now();
    const fromTimestamp = from || (toTimestamp - periodMs * (count + 10));

    const res = await this._send(PT.GET_TRENDBARS_REQ, {
      ctidTraderAccountId: config.ctraderAccountId,
      symbolId,
      period,
      fromTimestamp,
      toTimestamp,
      count,
      quoteType, // 1 = BID, 2 = ASK
    });

    const bars = res.trendbar ?? [];
    if (bars.length === 0) throw new Error(`No trendbar data for ${instrument}`);

    // cTrader prices are integers representing price × 100000
    const D = 100000;

    return bars.map((bar) => {
      const low   = bar.low   / D;
      const open  = (bar.low + (bar.deltaOpen  ?? 0)) / D;
      const close = (bar.low + (bar.deltaClose ?? 0)) / D;
      const high  = (bar.low + (bar.deltaHigh  ?? 0)) / D;

      return {
        time:     new Date(Number(bar.utcTimestampInMinutes) * 60_000).toISOString(),
        complete: true,
        volume:   bar.volume ?? 0,
        mid: {
          o: open.toFixed(5),
          h: high.toFixed(5),
          l: low.toFixed(5),
          c: close.toFixed(5),
        },
      };
    });
  }

  // ─── Account ───────────────────────────────────────────────────────────────

  async getAccount() {
    const res = await this._send(PT.TRADER_REQ, {
      payloadType: PT.TRADER_REQ,
      ctidTraderAccountId: Long.fromValue(config.ctraderAccountId),
    });

    const t = res.trader;
    // moneyDigits is the exponent (usually 2 for USD, but could be more)
    const d = Math.pow(10, t.moneyDigits || 2);

    return {
      balance:  (t.balance  / d).toFixed(2),
      equity:   ((t.balance + (t.unrealizedGrossProfit ?? 0)) / d).toFixed(2),
      currency: "USD",
    };
  }

  async getSymbol(symbolName) {
    if (this.symbols.has(symbolName)) return this.symbols.get(symbolName);

    // 1. Get the light symbol to find the symbolId
    const listRes = await this._send(PT.SYMBOLS_LIST_REQ, {
      payloadType: PT.SYMBOLS_LIST_REQ,
      ctidTraderAccountId: Long.fromValue(config.ctraderAccountId),
      includeArchivedSymbols: false,
    });

    // Try multiple name variations: EUR_USD -> EUR/USD, EURUSD, EUR_USD
    const variations = [
      symbolName.replace("_", "/"),
      symbolName.replace("_", ""),
      symbolName
    ];

    let light;
    for (const v of variations) {
      light = listRes.symbol.find(s => s.symbolName === v);
      if (light) break;
    }

    if (!light) throw new Error(`Symbol ${symbolName} not found in broker list.`);

    // 2. Get full symbol details
    const res = await this._send(PT.SYMBOL_BY_ID_REQ, {
      payloadType: PT.SYMBOL_BY_ID_REQ,
      ctidTraderAccountId: Long.fromValue(config.ctraderAccountId),
      symbolId: [light.symbolId],
    });

    const s = res.symbol[0];
    const details = {
      id:          Long.fromValue(s.symbolId).toNumber(),
      name:        s.symbolName,
      digits:      s.digits,
      pipPosition: s.pipPosition,
      minVolume:   Long.fromValue(s.minVolume || 0).toNumber() / 100,
      stepVolume:  Long.fromValue(s.stepVolume || 0).toNumber() / 100,
      maxVolume:   Long.fromValue(s.maxVolume || 0).toNumber() / 100,
    };

    this.symbols.set(symbolName, details);
    return details;
  }

  // ─── Orders ────────────────────────────────────────────────────────────────

  /**
   * High-level wrapper for index.js
   */
  async openPosition(pair, action, units, stopLoss, takeProfit, entryPriceHint) {
    // Ensure we have symbol details (for stepVolume/minVolume) before opening
    await this.getSymbol(pair);

    const isBuy = action === "BUY";
    const signedUnits = isBuy ? units : -units;

    let entryPrice = entryPriceHint;

    // If no hint provided, we need the latest price for relative SL/TP calculation
    if (!entryPrice) {
      const candles = await this.getCandles(pair, "M1", 1);
      entryPrice = candles[0].mid.c;
    }

    const res = await this.createOrder({
      instrument: pair,
      units: signedUnits,
      stopLoss,
      takeProfit,
      entryPrice
    });

    return {
      positionId: res.id,
      price: res.price
    };
  }

  /**
   * Place a market order with bracket stop loss + take profit
   *
   * @param {object} p
   * @param {string} p.instrument  e.g. "EUR_USD"
   * @param {number} p.units       positive = BUY, negative = SELL
   * @param {string} p.stopLoss    absolute price e.g. "1.08390"
   * @param {string} p.takeProfit  absolute price e.g. "1.08516"
   * @param {number} p.entryPrice  reference price for relative SL/TP calculation
   */
  async createOrder({ instrument, units, stopLoss, takeProfit, entryPrice }) {
    const symbolId = this._resolveSymbolId(instrument);
    const isBuy    = units > 0;
    const absUnits = Math.abs(units);

    // cTrader volume: 1 unit = 100 in their internal format (0.01 units)
    let volume     = absUnits * 100;

    // Ensure volume is a multiple of stepVolume (Phase 4 fix)
    const symbol = this.symbols.get(instrument);
    if (symbol && symbol.stepVolume) {
      const internalStep = symbol.stepVolume * 100;
      const internalMin  = (symbol.minVolume || 0) * 100;

      // Round down to nearest step
      volume = Math.floor(volume / internalStep) * internalStep;

      // Ensure it's at least the minimum volume
      if (volume < internalMin) {
        volume = internalMin;
      }
    }

    const payload = {
      payloadType: PT.NEW_ORDER_REQ,
      ctidTraderAccountId: Long.fromValue(config.ctraderAccountId),
      symbolId: Long.fromValue(symbolId),
      orderType:    1, // MARKET
      tradeSide:    isBuy ? 1 : 2, // BUY : SELL
      volume: Long.fromValue(volume),
    };

    // Slippage protection (Phase 3): max 2 pips deviation from expected price
    const maxSlippagePips = config.maxSlippagePips || 2;
    const isJPY = instrument.includes("JPY");
    const pipSize = isJPY ? 0.01 : 0.0001;
    const slippagePoints = Math.round(maxSlippagePips * pipSize * 100000);
    if (slippagePoints > 0) {
      payload.slippage = Long.fromValue(slippagePoints);
    }

    // For MARKET orders, cTrader requires relative SL/TP
    // Specified in 1/100000 of unit of a price
    if (stopLoss && entryPrice) {
      const dist = Math.abs(parseFloat(stopLoss) - entryPrice);
      payload.relativeStopLoss = Long.fromValue(Math.round(dist * 100000));
    }
    if (takeProfit && entryPrice) {
      const dist = Math.abs(parseFloat(takeProfit) - entryPrice);
      payload.relativeTakeProfit = Long.fromValue(Math.round(dist * 100000));
    }

    console.log("DEBUG: Order payload:", JSON.stringify(payload, (k, v) => typeof v === 'bigint' ? v.toString() : v));

    // Subscribe to execution events BEFORE sending the order
    // We want the ORDER_FILLED event specifically (executionType = 3)
    const execPromise = this._waitForPayloadType(PT.EXECUTION_EVENT, 20_000, (p) => {
        return p.executionType === 3 || p.executionType === "ORDER_FILLED";
    });
    const errPromise  = this._waitForPayloadType(PT.ORDER_ERROR_EVENT, 20_000);

    await this._send(PT.NEW_ORDER_REQ, payload, { expectEvent: true });

    // Wait for execution OR error — whichever comes first
    const result = await Promise.race([execPromise, errPromise]);

    if (!result || result._eventType === PT.ORDER_ERROR_EVENT) {
      const errorMsg = result ? `Order rejected: ${result.errorCode} — ${result.description ?? ""}` : "Order timeout/unknown error";
      throw new Error(errorMsg);
    }

    const deal     = result.deal     ?? {};
    const position = result.position ?? {};

    // Note: deal.executionPrice is already a double in some versions, 
    // but in others it might be int64 scaled by 10^5.
    // Based on ProtoOADeal definition it is 'optional double executionPrice = 10'.
    // However, if we get a very large number, we might need to divide it.
    let execPrice = deal.executionPrice ?? 0;
    if (execPrice > 1000) {
      // If it's something like 117240, it's scaled int64 (should have been double)
      execPrice = execPrice / 100000;
    }

    return {
      id:         position.positionId ?? deal.dealId ?? "unknown",
      price:      execPrice,
      units:      absUnits,
      instrument,
      time:       new Date().toISOString(),
    };
  }

  /**
   * Close an open position by positionId
   */
  async closeTrade(positionId) {
    // We need to get the current volume of the position first
    // Use a large volume — cTrader will cap it to the actual open volume
    await this._send(PT.CLOSE_POSITION_REQ, {
      ctidTraderAccountId: config.ctraderAccountId,
      positionId:          positionId,
      volume:              999_999_999,   // max out → closes entire position
    });
  }

  /**
   * Update SL/TP of an existing position
   */
  async amendPositionSLTP(positionId, stopLoss, takeProfit) {
    await this._send(PT.AMEND_POSITION_SLTP_REQ, {
      ctidTraderAccountId: config.ctraderAccountId,
      positionId:          positionId,
      stopLoss:            stopLoss ? Number(parseFloat(stopLoss).toFixed(5)) : undefined,
      takeProfit:          takeProfit ? Number(parseFloat(takeProfit).toFixed(5)) : undefined,
    });
  }

  /**
   * Fetch all open positions for the account
   */
  async reconcile() {
    const res = await this._send(PT.RECONCILE_REQ, {
      ctidTraderAccountId: config.ctraderAccountId,
      returnProtectionOrders: true,
    });
    return res.position || [];
  }

  // ─── Symbol ID Resolution ──────────────────────────────────────────────────

  _resolveSymbolId(instrument) {
    // Check cache first
    if (this.symbols.has(instrument)) {
      return this.symbols.get(instrument).id;
    }

    const id = (config.ctraderSymbolIds ?? {})[instrument];
    if (!id) {
      throw new Error(
        `No symbol ID found for "${instrument}". ` +
        `Run "node get-symbols.js" and update config.ctraderSymbolIds.`
      );
    }
    return id;
  }

  /**
   * Register a callback for a specific unsolicited event (e.g. SPOT_EVENT)
   */
  on(payloadType, callback) {
    if (!this.eventListeners.has(payloadType)) {
      this.eventListeners.set(payloadType, []);
    }
    this.eventListeners.get(payloadType).push(callback);
  }

  /**
   * Remove a callback
   */
  off(payloadType, callback) {
    if (this.eventListeners.has(payloadType)) {
      const listeners = this.eventListeners.get(payloadType);
      const index = listeners.indexOf(callback);
      if (index !== -1) listeners.splice(index, 1);
    }
  }

  /**
   * Subscribe to live tick updates (spot events) for a symbol
   */
  async subscribeTicks(instrument) {
    const symbolId = this._resolveSymbolId(instrument);
    await this._send(PT.SUBSCRIBE_SPOTS_REQ, {
      ctidTraderAccountId: config.ctraderAccountId,
      symbolId: [symbolId],
    });
  }

  /**
   * Fetch current spread in pips for a symbol
   */
  async getSpread(instrument) {
    const symbolId = this._resolveSymbolId(instrument);

    return new Promise(async (resolve, reject) => {
      const onSpot = (payload) => {
        if (String(payload.symbolId) === String(symbolId) && (payload.bid || payload.ask)) {
          // Note: cTrader spot events might only contain bid OR ask if only one changed.
          // For a simple spread check, we need both. If only one is present, we wait for the next.
          // BUT, we can also use the last known if we had a cache. 
          // For simplicity here, we just wait for one that has both or wait for a few.
          if (payload.bid && payload.ask) {
            this.off(PT.SPOT_EVENT, onSpot);
            const bid = payload.bid / 100000;
            const ask = payload.ask / 100000;
            const isJPY = instrument.includes("JPY");
            const pipSize = isJPY ? 0.01 : 0.0001;
            const spreadPips = (ask - bid) / pipSize;
            resolve(spreadPips);
          }
        }
      };

      this.on(PT.SPOT_EVENT, onSpot);

      try {
        await this.subscribeTicks(instrument);
        // Timeout if no quote in 5s
        setTimeout(() => {
          this.off(PT.SPOT_EVENT, onSpot);
          reject(new Error("Timeout waiting for spread quote"));
        }, 5000);
      } catch (err) {
        this.off(PT.SPOT_EVENT, onSpot);
        reject(err);
      }
    });
  }

  // ─── Messaging ─────────────────────────────────────────────────────────────

  /**
   * Send a message and (optionally) wait for the corresponding response.
   */
  _send(payloadType, payload, { expectEvent = false } = {}) {
    // Guard: don't send on a closed/closing socket
    if (!this.ws || this.ws.readyState !== WebSocket.OPEN) {
      return Promise.reject(new Error("WebSocket not open — skipping send"));
    }

    const clientMsgId = `m${this.msgCounter++}`;

    // 1. Encode the inner payload
    const typeName = PT_NAMES[payloadType];
    if (!typeName) throw new Error(`Unknown payloadType: ${payloadType}`);

    const InnerType = this.root.lookupType(typeName);
    const innerMsg = InnerType.create(payload);
    const innerBuffer = InnerType.encode(innerMsg).finish();

    // 2. Wrap in ProtoMessage
    const protoMsg = { payloadType, payload: innerBuffer, clientMsgId };
    const OuterType = this.root.lookupType("ProtoMessage");
    const outerMsg = OuterType.create(protoMsg);
    const outerBuffer = OuterType.encode(outerMsg).finish();

    // 3. Send the outer buffer as a binary frame (NO 4-byte header for WebSocket)
    const frame = outerBuffer;

    return new Promise((resolve, reject) => {
      if (!expectEvent) {
        this.pendingRequests.set(clientMsgId, { resolve, reject });
        setTimeout(() => {
          if (this.pendingRequests.has(clientMsgId)) {
            this.pendingRequests.delete(clientMsgId);
            reject(new Error(`Timeout waiting for response to ${typeName} (${payloadType})`));
          }
        }, 15_000);
      }

      this.ws.send(frame, { binary: true }, (err) => {
        if (err) {
          this.pendingRequests.delete(clientMsgId);
          reject(err);
        } else if (expectEvent) {
          resolve(null);
        }
      });
    });
  }

  /**
   * Wait for a specific unsolicited event payload type (e.g. EXECUTION_EVENT)
   * with an optional filter function.
   */
  _waitForPayloadType(payloadType, timeoutMs = 15_000, filterFn = null) {
    return new Promise((resolve, reject) => {
      const handler = (payload) => {
        if (filterFn && !filterFn(payload)) return;

        clearTimeout(timer);
        this.off(payloadType, handler);
        resolve({ ...payload, _eventType: payloadType });
      };

      const timer = setTimeout(() => {
        this.off(payloadType, handler);
        reject(new Error(`Timeout waiting for event ${payloadType}`));
      }, timeoutMs);

      this.on(payloadType, handler);
    });
  }

  _onMessage(raw) {
    let msg, payload;
    try {
      ({ msg, payload } = this._parseFrame(raw));
    } catch (err) {
      console.error("❌ Protobuf decode error:", err.message);
      return; 
    }

    const { clientMsgId, payloadType } = msg;

    // Error response — reject the pending request
    if (payloadType === PT.ERROR_RES) {
      const pending = this.pendingRequests.get(clientMsgId);
      if (pending) {
        this.pendingRequests.delete(clientMsgId);
        const errorCode = payload?.errorCode || "UNKNOWN";
        const description = payload?.description || "";
        console.error(`❌ cTrader Error [${clientMsgId}]: ${errorCode} - ${description}`);
        pending.reject(
          new Error(`cTrader error ${errorCode}: ${description}`)
        );
      }
      return;
    }

    // Normal response — resolve the pending request
    if (clientMsgId && this.pendingRequests.has(clientMsgId)) {
      const pending = this.pendingRequests.get(clientMsgId);
      this.pendingRequests.delete(clientMsgId);
      pending.resolve(payload);
    }

    // Unsolicited events — trigger registered listeners
    if (this.eventListeners.has(payloadType)) {
      this.eventListeners.get(payloadType).forEach(cb => cb(payload));
    }
  }

  /**
   * Parse a cTrader binary frame (ProtoMessage)
   */
  _parseFrame(raw) {
    // raw is a Buffer (or ArrayBuffer) from ws
    const buffer = Buffer.from(raw);

    // NO 4-byte header for WebSocket
    const payloadBuffer = buffer;

    // Decode ProtoMessage
    const ProtoMessage = this.root.lookupType("ProtoMessage");
    const msg = ProtoMessage.decode(payloadBuffer);

    // Decode nested payload
    const typeName = PT_NAMES[msg.payloadType];
    let payload = {};
    if (typeName && msg.payload) {
      const InnerType = this.root.lookupType(typeName);
      payload = InnerType.toObject(InnerType.decode(msg.payload), {
        enums: String, // Convert enums to strings for convenience
        longs: Number, // Convert longs to numbers
        defaults: true,
      });
    }

    return { msg, payload };
  }

  // ─── Heartbeat ─────────────────────────────────────────────────────────────

  _startHeartbeat() {
    this.heartbeatTimer = setInterval(() => {
      if (this.connected) {
        this._send(PT.HEARTBEAT, {}).catch(() => {});
      }
    }, 20_000);
  }

  /**
   * WebSocket-level ping to prevent GCP/cloud firewall idle timeout.
   * GCP drops idle TCP connections after ~10 minutes; this keeps them alive.
   */
  _startKeepalive() {
    const KEEPALIVE_MS = 4 * 60 * 1000; // every 4 minutes
    this.keepaliveTimer = setInterval(() => {
      if (this.ws && this.ws.readyState === WebSocket.OPEN) {
        this.ws.ping?.();
      }
    }, KEEPALIVE_MS);
  }

  // ─── Connection Health Monitor (Phase 4) ─────────────────────────────────

  _startHealthMonitor() {
    const timeoutMs = (config.connectionTimeoutSeconds || 10) * 1000;
    this.healthCheckTimer = setInterval(() => {
      const silenceMs = Date.now() - this.lastMessageTime;
      if (silenceMs > timeoutMs && this.connected) {
        const msg = ` EMERGENCY: No data from cTrader for ${(silenceMs / 1000).toFixed(0)}s (limit: ${config.connectionTimeoutSeconds}s)`;
        console.error(msg);
        logConnectionAlert(msg);
        if (this.onConnectionLost) {
          this.onConnectionLost(msg);
        }
      }
    }, 5_000); // Check every 5s
  }
}

function sleep(ms) {
  return new Promise((r) => setTimeout(r, ms));
}

/**
 * IC Markets — cTrader Open API Client
 *
 * Protocol : WebSocket + JSON (port 5036)
 * Docs     : https://help.ctrader.com/open-api/
 *
 * Authentication flow (happens inside authenticate()):
 *   1. ProtoOAApplicationAuthReq  → authenticate the app
 *   2. ProtoOAAccountAuthReq      → authenticate the trading account
 *
 * Key operations:
 *   getCandles()   → ProtoOAGetTrendbarsReq
 *   getAccount()   → ProtoOATraderReq
 *   createOrder()  → ProtoOANewOrderReq  (waits for ExecutionEvent)
 *   closeTrade()   → ProtoOAClosePositionReq
 */

import WebSocket from "ws";
import fs from "fs";
import protobuf from "protobufjs";
import Long from "long";
import { config } from "./config.js";

function logConnectionAlert(message) {
  const entry = JSON.stringify({ timestamp: new Date().toISOString(), type: "connection_alert", message }) + "\n";
  try { fs.appendFileSync("activity.log", entry); } catch {}
}

// ─── Payload type constants (Protobuf version) ──────────────────────────────
const PT = {
  ERROR_RES:           2142,
  HEARTBEAT:             51,
  APP_AUTH_REQ:        2100,
  APP_AUTH_RES:        2101,
  ACCOUNT_AUTH_REQ:    2102,
  ACCOUNT_AUTH_RES:    2103,
  VERSION_REQ:         2104,
  VERSION_RES:         2105,
  NEW_ORDER_REQ:       2106,
  TRADER_REQ:          2121,
  TRADER_RES:          2122,
  EXECUTION_EVENT:     2126,
  SUBSCRIBE_SPOTS_REQ: 2127,
  SUBSCRIBE_SPOTS_RES: 2128,
  SPOT_EVENT:          2131,
  ORDER_ERROR_EVENT:   2132,
  RECONCILE_REQ:       2124,
  RECONCILE_RES:       2125,
  GET_TRENDBARS_REQ:   2137,
  GET_TRENDBARS_RES:   2138,
  CLOSE_POSITION_REQ:  2111,
  AMEND_POSITION_SLTP_REQ: 2110,
  SYMBOLS_LIST_REQ:    2114,
  SYMBOLS_LIST_RES:    2115,
  SYMBOL_BY_ID_REQ:    2116,
  SYMBOL_BY_ID_RES:    2117,
  GET_ACCOUNTS_BY_ACCESS_TOKEN_REQ: 2149,
  GET_ACCOUNTS_BY_ACCESS_TOKEN_RES: 2150,
};

// Map of payloadType → Proto message name (for decoding)
const PT_NAMES = {
  51:   "ProtoHeartbeatEvent",
  2100: "ProtoOAApplicationAuthReq",
  2101: "ProtoOAApplicationAuthRes",
  2102: "ProtoOAAccountAuthReq",
  2103: "ProtoOAAccountAuthRes",
  2104: "ProtoOAVersionReq",
  2105: "ProtoOAVersionRes",
  2106: "ProtoOANewOrderReq",
  2114: "ProtoOASymbolsListReq",
  2115: "ProtoOASymbolsListRes",
  2116: "ProtoOASymbolByIdReq",
  2117: "ProtoOASymbolByIdRes",
  2121: "ProtoOATraderReq",
  2122: "ProtoOATraderRes",
  2124: "ProtoOAReconcileReq",
  2125: "ProtoOAReconcileRes",
  2126: "ProtoOAExecutionEvent",
  2127: "ProtoOASubscribeSpotsReq",
  2128: "ProtoOASubscribeSpotsRes",
  2131: "ProtoOASpotEvent",
  2132: "ProtoOAOrderErrorEvent",
  2137: "ProtoOAGetTrendbarsReq",
  2138: "ProtoOAGetTrendbarsRes",
  2110: "ProtoOAAmendPositionSLTPReq",
  2111: "ProtoOAClosePositionReq",
  2142: "ProtoOAErrorRes",
  2149: "ProtoOAGetAccountListByAccessTokenReq",
  2150: "ProtoOAGetAccountListByAccessTokenRes",
};

// Granularity string → cTrader period integer
const PERIOD = {
  M1: 1, M2: 2, M3: 3, M4: 4, M5: 5,
  M10: 6, M15: 7, M30: 8,
  H1: 9, H4: 10, H12: 11,
  D1: 12, W1: 13, MN1: 14,
};

// Granularity → milliseconds (used for timestamp range calculation)
const PERIOD_MS = {
  M1: 60_000, M5: 300_000, M15: 900_000, M30: 1_800_000,
  H1: 3_600_000, H4: 14_400_000, D1: 86_400_000,
};

const RATE_LIMIT_ERROR_CODE = "REQUEST_FREQUENCY_EXCEEDED";

const THROTTLE_BYPASS_PAYLOAD_TYPES = new Set([
  PT.HEARTBEAT,
  PT.APP_AUTH_REQ,
  PT.ACCOUNT_AUTH_REQ,
  PT.NEW_ORDER_REQ,
  PT.CLOSE_POSITION_REQ,
  PT.AMEND_POSITION_SLTP_REQ,
]);

export class ICMarketsClient {
  constructor() {
    this.ws              = null;
    this.connected       = false;
    this.pendingRequests = new Map();   // msgId → { resolve, reject }
    this.eventListeners  = new Map();   // payloadType → [callbacks]
    this.msgCounter      = 1;
    this.heartbeatTimer  = null;
    this.reconnecting    = false;
    this.root            = null;
    this.proto           = null;        // Cache for loaded proto definitions
    this.symbols         = new Map();   // Cache for symbol details
    // Connection health monitoring (Phase 4)
    this.lastMessageTime = Date.now();
    this.healthCheckTimer = null;
    this.onConnectionLost = null;       // Callback for emergency alert
    this.keepaliveTimer  = null;        // GCP idle connection keepalive
    this.nonTradeQueue = [];
    this.processingNonTradeQueue = false;
    this.lastNonTradeRequestAt = 0;
    this.nonTradeRequestTimestamps = [];
    this.rateLimitBackoffUntil = 0;
  }

  // ─── Connection ────────────────────────────────────────────────────────────

  async _loadProto() {
    if (this.root) return;
    this.root = await protobuf.load([
      "OpenApiCommonMessages.proto",
      "OpenApiCommonModelMessages.proto",
      "OpenApiMessages.proto",
      "OpenApiModelMessages.proto"
    ]);
  }

  async connect() {
    await this._loadProto();
    const host = config.ctraderEnv === "live"
      ? "live.ctraderapi.com"
      : "demo.ctraderapi.com";

    return new Promise((resolve, reject) => {
      let settled = false;
      const connectTimeout = setTimeout(() => {
        if (settled) return;
        settled = true;
        try { this.ws?.terminate(); } catch {}
        reject(new Error(`Timeout connecting to cTrader WebSocket (${host}:5035)`));
      }, 15_000);

      // Protobuf port is 5035
      this.ws = new WebSocket(`wss://${host}:5035`);

      this.ws.on("open", () => {
        if (settled) return;
        settled = true;
        clearTimeout(connectTimeout);
        this.connected = true;
        this.lastMessageTime = Date.now();
        this._startHeartbeat();
        this._startHealthMonitor();
        this._startKeepalive();
        resolve();
      });

      this.ws.on("message", (raw) => {
        this.lastMessageTime = Date.now();
        this._onMessage(raw);
      });

      this.ws.on("error", (err) => {
        if (!this.connected && !settled) {
          settled = true;
          clearTimeout(connectTimeout);
          reject(err);
        }
        console.error("❌ WebSocket error:", err.message);
      });

      this.ws.on("close", () => {
        clearTimeout(connectTimeout);
        const wasConnected = this.connected;
        this.connected = false;
        clearInterval(this.heartbeatTimer);
        clearInterval(this.healthCheckTimer);
        clearInterval(this.keepaliveTimer);
        // Reject all pending requests — socket is dead
        for (const [id, pending] of this.pendingRequests) {
          pending.reject(new Error("WebSocket closed while waiting for response"));
        }
        this.pendingRequests.clear();
        if (wasConnected && !this.reconnecting) this._scheduleReconnect();
      });
    });
  }

  async _scheduleReconnect() {
    this.reconnecting = true;
    console.log("\n⚠️  Connection lost — reconnecting in 5s...");
    await sleep(5000);
    try {
      await this.connect();
      await this.authenticate();
      console.log("✅ Reconnected.\n");
    } catch (err) {
      console.error("Reconnect failed:", err.message);
    } finally {
      this.reconnecting = false;
    }
  }

  // ─── Authentication ────────────────────────────────────────────────────────

  async authenticate() {
    // Step 1: authenticate the application
    await this._send(PT.APP_AUTH_REQ, {
      clientId:     config.ctraderClientId,
      clientSecret: config.ctraderClientSecret,
    });

    // Step 2: authenticate the trading account
    await this._send(PT.ACCOUNT_AUTH_REQ, {
      ctidTraderAccountId: Long.fromValue(config.ctraderAccountId),
      accessToken:         config.ctraderAccessToken,
    });
  }

  // ─── Market Data ───────────────────────────────────────────────────────────

  /**
   * Fetch historical candles and return them in the standard format
   * used by indicators.js (same shape as OANDA/Alpaca candles)
   */
  async getCandles(instrument, granularity = "M5", count = 100, from = null, to = null, quoteType = 1) {
    const symbolId = this._resolveSymbolId(instrument);
    const period   = PERIOD[granularity];
    if (!period) throw new Error(`Unknown granularity: ${granularity}`);

    const periodMs    = PERIOD_MS[granularity] ?? 300_000;
    const toTimestamp = to || Date.now();
    const fromTimestamp = from || (toTimestamp - periodMs * (count + 10));

    const res = await this._send(PT.GET_TRENDBARS_REQ, {
      ctidTraderAccountId: config.ctraderAccountId,
      symbolId,
      period,
      fromTimestamp,
      toTimestamp,
      count,
      quoteType, // 1 = BID, 2 = ASK
    });

    const bars = res.trendbar ?? [];
    if (bars.length === 0) throw new Error(`No trendbar data for ${instrument}`);

    // cTrader prices are integers representing price × 100000
    const D = 100000;

    return bars.map((bar) => {
      const low   = bar.low   / D;
      const open  = (bar.low + (bar.deltaOpen  ?? 0)) / D;
      const close = (bar.low + (bar.deltaClose ?? 0)) / D;
      const high  = (bar.low + (bar.deltaHigh  ?? 0)) / D;

      return {
        time:     new Date(Number(bar.utcTimestampInMinutes) * 60_000).toISOString(),
        complete: true,
        volume:   bar.volume ?? 0,
        mid: {
          o: open.toFixed(5),
          h: high.toFixed(5),
          l: low.toFixed(5),
          c: close.toFixed(5),
        },
      };
    });
  }

  // ─── Account ───────────────────────────────────────────────────────────────

  async getAccount() {
    const res = await this._send(PT.TRADER_REQ, {
      payloadType: PT.TRADER_REQ,
      ctidTraderAccountId: Long.fromValue(config.ctraderAccountId),
    });

    const t = res.trader;
    // moneyDigits is the exponent (usually 2 for USD, but could be more)
    const d = Math.pow(10, t.moneyDigits || 2);

    return {
      balance:  (t.balance  / d).toFixed(2),
      equity:   ((t.balance + (t.unrealizedGrossProfit ?? 0)) / d).toFixed(2),
      currency: "USD",
    };
  }

  async getSymbol(symbolName, { priority = "normal" } = {}) {
    if (this.symbols.has(symbolName)) return this.symbols.get(symbolName);

    // 1. Get the light symbol to find the symbolId
    const listRes = await this._send(PT.SYMBOLS_LIST_REQ, {
      payloadType: PT.SYMBOLS_LIST_REQ,
      ctidTraderAccountId: Long.fromValue(config.ctraderAccountId),
      includeArchivedSymbols: false,
    }, { priority });

    // Try multiple name variations: EUR_USD -> EUR/USD, EURUSD, EUR_USD
    const variations = [
      symbolName.replace("_", "/"),
      symbolName.replace("_", ""),
      symbolName
    ];

    let light;
    for (const v of variations) {
      light = listRes.symbol.find(s => s.symbolName === v);
      if (light) break;
    }

    if (!light) throw new Error(`Symbol ${symbolName} not found in broker list.`);

    // 2. Get full symbol details
    const res = await this._send(PT.SYMBOL_BY_ID_REQ, {
      payloadType: PT.SYMBOL_BY_ID_REQ,
      ctidTraderAccountId: Long.fromValue(config.ctraderAccountId),
      symbolId: [light.symbolId],
    }, { priority });

    const s = res.symbol[0];
    const details = {
      id:          Long.fromValue(s.symbolId).toNumber(),
      name:        s.symbolName,
      digits:      s.digits,
      pipPosition: s.pipPosition,
      minVolume:   Long.fromValue(s.minVolume || 0).toNumber() / 100,
      stepVolume:  Long.fromValue(s.stepVolume || 0).toNumber() / 100,
      maxVolume:   Long.fromValue(s.maxVolume || 0).toNumber() / 100,
    };

    this.symbols.set(symbolName, details);
    return details;
  }

  // ─── Orders ────────────────────────────────────────────────────────────────

  /**
   * High-level wrapper for index.js
   */
  async openPosition(pair, action, units, stopLoss, takeProfit, entryPriceHint) {
    // Best-effort symbol details lookup for stepVolume/minVolume. If cTrader
    // rate-limits metadata, still place the order using config.ctraderSymbolIds.
    try {
      await this.getSymbol(pair, { priority: "high" });
    } catch (err) {
      console.warn(`  ⚠️  ${pair} symbol details unavailable before order: ${err.message}`);
    }

    const isBuy = action === "BUY";
    const signedUnits = isBuy ? units : -units;

    let entryPrice = entryPriceHint;

    // If no hint provided, we need the latest price for relative SL/TP calculation
    if (!entryPrice) {
      const candles = await this.getCandles(pair, "M1", 1);
      entryPrice = candles[0].mid.c;
    }

    const res = await this.createOrder({
      instrument: pair,
      units: signedUnits,
      stopLoss,
      takeProfit,
      entryPrice
    });

    return {
      positionId: res.id,
      price: res.price
    };
  }

  /**
   * Place a market order with bracket stop loss + take profit
   *
   * @param {object} p
   * @param {string} p.instrument  e.g. "EUR_USD"
   * @param {number} p.units       positive = BUY, negative = SELL
   * @param {string} p.stopLoss    absolute price e.g. "1.08390"
   * @param {string} p.takeProfit  absolute price e.g. "1.08516"
   * @param {number} p.entryPrice  reference price for relative SL/TP calculation
   */
  async createOrder({ instrument, units, stopLoss, takeProfit, entryPrice }) {
    const symbolId = this._resolveSymbolId(instrument);
    const isBuy    = units > 0;
    const absUnits = Math.abs(units);

    // cTrader volume: 1 unit = 100 in their internal format (0.01 units)
    let volume     = absUnits * 100;

    // Ensure volume is a multiple of stepVolume (Phase 4 fix)
    const symbol = this.symbols.get(instrument);
    if (symbol && symbol.stepVolume) {
      const internalStep = symbol.stepVolume * 100;
      const internalMin  = (symbol.minVolume || 0) * 100;

      // Round down to nearest step
      volume = Math.floor(volume / internalStep) * internalStep;

      // Ensure it's at least the minimum volume
      if (volume < internalMin) {
        volume = internalMin;
      }
    }

    const payload = {
      payloadType: PT.NEW_ORDER_REQ,
      ctidTraderAccountId: Long.fromValue(config.ctraderAccountId),
      symbolId: Long.fromValue(symbolId),
      orderType:    1, // MARKET
      tradeSide:    isBuy ? 1 : 2, // BUY : SELL
      volume: Long.fromValue(volume),
    };

    // Slippage protection (Phase 3): max 2 pips deviation from expected price
    const maxSlippagePips = config.maxSlippagePips || 2;
    const isJPY = instrument.includes("JPY");
    const pipSize = isJPY ? 0.01 : 0.0001;
    const slippagePoints = Math.round(maxSlippagePips * pipSize * 100000);
    if (slippagePoints > 0) {
      payload.slippage = Long.fromValue(slippagePoints);
    }

    // For MARKET orders, cTrader requires relative SL/TP
    // Specified in 1/100000 of unit of a price
    if (stopLoss && entryPrice) {
      const dist = Math.abs(parseFloat(stopLoss) - entryPrice);
      payload.relativeStopLoss = Long.fromValue(Math.round(dist * 100000));
    }
    if (takeProfit && entryPrice) {
      const dist = Math.abs(parseFloat(takeProfit) - entryPrice);
      payload.relativeTakeProfit = Long.fromValue(Math.round(dist * 100000));
    }

    console.log("DEBUG: Order payload:", JSON.stringify(payload, (k, v) => typeof v === 'bigint' ? v.toString() : v));

    // Subscribe to execution events BEFORE sending the order
    // We want the ORDER_FILLED event specifically (executionType = 3)
    const execPromise = this._waitForPayloadType(PT.EXECUTION_EVENT, 20_000, (p) => {
        return p.executionType === 3 || p.executionType === "ORDER_FILLED";
    });
    const errPromise  = this._waitForPayloadType(PT.ORDER_ERROR_EVENT, 20_000);

    await this._send(PT.NEW_ORDER_REQ, payload, { expectEvent: true });

    // Wait for execution OR error — whichever comes first
    const result = await Promise.race([execPromise, errPromise]);

    if (!result || result._eventType === PT.ORDER_ERROR_EVENT) {
      const errorMsg = result ? `Order rejected: ${result.errorCode} — ${result.description ?? ""}` : "Order timeout/unknown error";
      throw new Error(errorMsg);
    }

    const deal     = result.deal     ?? {};
    const position = result.position ?? {};

    // Note: deal.executionPrice is already a double in some versions, 
    // but in others it might be int64 scaled by 10^5.
    // Based on ProtoOADeal definition it is 'optional double executionPrice = 10'.
    // However, if we get a very large number, we might need to divide it.
    let execPrice = deal.executionPrice ?? 0;
    if (execPrice > 1000) {
      // If it's something like 117240, it's scaled int64 (should have been double)
      execPrice = execPrice / 100000;
    }

    return {
      id:         position.positionId ?? deal.dealId ?? "unknown",
      price:      execPrice,
      units:      absUnits,
      instrument,
      time:       new Date().toISOString(),
    };
  }

  /**
   * Close an open position by positionId
   */
  async closeTrade(positionId) {
    // We need to get the current volume of the position first
    // Use a large volume — cTrader will cap it to the actual open volume
    await this._send(PT.CLOSE_POSITION_REQ, {
      ctidTraderAccountId: config.ctraderAccountId,
      positionId:          positionId,
      volume:              999_999_999,   // max out → closes entire position
    });
  }

  /**
   * Update SL/TP of an existing position
   */
  async amendPositionSLTP(positionId, stopLoss, takeProfit) {
    await this._send(PT.AMEND_POSITION_SLTP_REQ, {
      ctidTraderAccountId: config.ctraderAccountId,
      positionId:          positionId,
      stopLoss:            stopLoss ? Number(parseFloat(stopLoss).toFixed(5)) : undefined,
      takeProfit:          takeProfit ? Number(parseFloat(takeProfit).toFixed(5)) : undefined,
    });
  }

  /**
   * Fetch all open positions for the account
   */
  async reconcile() {
    const res = await this._send(PT.RECONCILE_REQ, {
      ctidTraderAccountId: config.ctraderAccountId,
      returnProtectionOrders: true,
    });
    return res.position || [];
  }

  // ─── Symbol ID Resolution ──────────────────────────────────────────────────

  _resolveSymbolId(instrument) {
    // Check cache first
    if (this.symbols.has(instrument)) {
      return this.symbols.get(instrument).id;
    }

    const id = (config.ctraderSymbolIds ?? {})[instrument];
    if (!id) {
      throw new Error(
        `No symbol ID found for "${instrument}". ` +
        `Run "node get-symbols.js" and update config.ctraderSymbolIds.`
      );
    }
    return id;
  }

  /**
   * Register a callback for a specific unsolicited event (e.g. SPOT_EVENT)
   */
  on(payloadType, callback) {
    if (!this.eventListeners.has(payloadType)) {
      this.eventListeners.set(payloadType, []);
    }
    this.eventListeners.get(payloadType).push(callback);
  }

  /**
   * Remove a callback
   */
  off(payloadType, callback) {
    if (this.eventListeners.has(payloadType)) {
      const listeners = this.eventListeners.get(payloadType);
      const index = listeners.indexOf(callback);
      if (index !== -1) listeners.splice(index, 1);
    }
  }

  /**
   * Subscribe to live tick updates (spot events) for a symbol
   */
  async subscribeTicks(instrument) {
    const symbolId = this._resolveSymbolId(instrument);
    await this._send(PT.SUBSCRIBE_SPOTS_REQ, {
      ctidTraderAccountId: config.ctraderAccountId,
      symbolId: [symbolId],
    });
  }

  /**
   * Fetch current spread in pips for a symbol
   */
  async getSpread(instrument) {
    const symbolId = this._resolveSymbolId(instrument);

    return new Promise(async (resolve, reject) => {
      const onSpot = (payload) => {
        if (String(payload.symbolId) === String(symbolId) && (payload.bid || payload.ask)) {
          // Note: cTrader spot events might only contain bid OR ask if only one changed.
          // For a simple spread check, we need both. If only one is present, we wait for the next.
          // BUT, we can also use the last known if we had a cache. 
          // For simplicity here, we just wait for one that has both or wait for a few.
          if (payload.bid && payload.ask) {
            this.off(PT.SPOT_EVENT, onSpot);
            const bid = payload.bid / 100000;
            const ask = payload.ask / 100000;
            const isJPY = instrument.includes("JPY");
            const pipSize = isJPY ? 0.01 : 0.0001;
            const spreadPips = (ask - bid) / pipSize;
            resolve(spreadPips);
          }
        }
      };

      this.on(PT.SPOT_EVENT, onSpot);

      try {
        await this.subscribeTicks(instrument);
        // Timeout if no quote in 5s
        setTimeout(() => {
          this.off(PT.SPOT_EVENT, onSpot);
          reject(new Error("Timeout waiting for spread quote"));
        }, 5000);
      } catch (err) {
        this.off(PT.SPOT_EVENT, onSpot);
        reject(err);
      }
    });
  }

  // ─── Messaging ─────────────────────────────────────────────────────────────

  /**
   * Send a message and (optionally) wait for the corresponding response.
   */
  _send(payloadType, payload, { expectEvent = false, priority = "normal" } = {}) {
    // Guard: don't send on a closed/closing socket
    if (!this.ws || this.ws.readyState !== WebSocket.OPEN) {
      return Promise.reject(new Error("WebSocket not open — skipping send"));
    }

    const clientMsgId = `m${this.msgCounter++}`;

    // 1. Encode the inner payload
    const typeName = PT_NAMES[payloadType];
    if (!typeName) throw new Error(`Unknown payloadType: ${payloadType}`);

    const InnerType = this.root.lookupType(typeName);
    const innerMsg = InnerType.create(payload);
    const innerBuffer = InnerType.encode(innerMsg).finish();

    // 2. Wrap in ProtoMessage
    const protoMsg = { payloadType, payload: innerBuffer, clientMsgId };
    const OuterType = this.root.lookupType("ProtoMessage");
    const outerMsg = OuterType.create(protoMsg);
    const outerBuffer = OuterType.encode(outerMsg).finish();

    // 3. Send the outer buffer as a binary frame (NO 4-byte header for WebSocket)
    const frame = outerBuffer;

    if (priority === "high" || THROTTLE_BYPASS_PAYLOAD_TYPES.has(payloadType)) {
      return this._sendFrame({ payloadType, typeName, clientMsgId, frame, expectEvent });
    }

    return this._enqueueNonTradeRequest({ payloadType, typeName, clientMsgId, frame, expectEvent });
  }

  _enqueueNonTradeRequest(request) {
    return new Promise((resolve, reject) => {
      this.nonTradeQueue.push({ ...request, resolve, reject });
      this._processNonTradeQueue().catch((err) => {
        console.error("❌ cTrader request queue error:", err.message);
      });
    });
  }

  async _processNonTradeQueue() {
    if (this.processingNonTradeQueue) return;
    this.processingNonTradeQueue = true;

    try {
      while (this.nonTradeQueue.length > 0) {
        const request = this.nonTradeQueue.shift();
        await this._waitForNonTradeSlot();
        this._recordNonTradeRequestSent();
        this._sendFrame(request).then(request.resolve, request.reject);
      }
    } finally {
      this.processingNonTradeQueue = false;
      if (this.nonTradeQueue.length > 0) {
        this._processNonTradeQueue().catch((err) => {
          console.error("❌ cTrader request queue error:", err.message);
        });
      }
    }
  }

  async _waitForNonTradeSlot() {
    const cfg = this._rateLimitConfig();

    while (true) {
      const now = Date.now();
      this.nonTradeRequestTimestamps = this.nonTradeRequestTimestamps.filter(ts => now - ts < 60_000);

      if (now < this.rateLimitBackoffUntil) {
        await sleep(Math.min(this.rateLimitBackoffUntil - now, 5_000));
        continue;
      }

      if (cfg.maxPerMinute > 0 && this.nonTradeRequestTimestamps.length >= cfg.maxPerMinute) {
        const oldest = this.nonTradeRequestTimestamps[0];
        await sleep(Math.max(250, oldest + 60_000 - now));
        continue;
      }

      const waitMs = cfg.minIntervalMs - (now - this.lastNonTradeRequestAt);
      if (waitMs > 0) {
        await sleep(waitMs);
        continue;
      }

      return;
    }
  }

  _recordNonTradeRequestSent() {
    const now = Date.now();
    this.lastNonTradeRequestAt = now;
    this.nonTradeRequestTimestamps.push(now);
  }

  _rateLimitConfig() {
    const cfg = config.ctraderRateLimit ?? {};
    return {
      minIntervalMs: Math.max(0, Number(cfg.nonTradeMinIntervalMs ?? 750)),
      maxPerMinute: Math.max(0, Number(cfg.maxNonTradeRequestsPerMinute ?? 40)),
      backoffMs: Math.max(1_000, Number(cfg.rateLimitBackoffMs ?? 30_000)),
    };
  }

  _sendFrame({ payloadType, typeName, clientMsgId, frame, expectEvent }) {
    return new Promise((resolve, reject) => {
      let timeoutId = null;
      const cleanupResolve = (payload) => {
        if (timeoutId) clearTimeout(timeoutId);
        resolve(payload);
      };
      const cleanupReject = (err) => {
        if (timeoutId) clearTimeout(timeoutId);
        reject(err);
      };

      if (!expectEvent) {
        this.pendingRequests.set(clientMsgId, { resolve: cleanupResolve, reject: cleanupReject });
        timeoutId = setTimeout(() => {
          if (this.pendingRequests.has(clientMsgId)) {
            this.pendingRequests.delete(clientMsgId);
            cleanupReject(new Error(`Timeout waiting for response to ${typeName} (${payloadType})`));
          }
        }, 15_000);
      }

      this.ws.send(frame, { binary: true }, (err) => {
        if (err) {
          this.pendingRequests.delete(clientMsgId);
          cleanupReject(err);
        } else if (expectEvent) {
          cleanupResolve(null);
        }
      });
    });
  }

  /**
   * Wait for a specific unsolicited event payload type (e.g. EXECUTION_EVENT)
   * with an optional filter function.
   */
  _waitForPayloadType(payloadType, timeoutMs = 15_000, filterFn = null) {
    return new Promise((resolve, reject) => {
      const handler = (payload) => {
        if (filterFn && !filterFn(payload)) return;

        clearTimeout(timer);
        this.off(payloadType, handler);
        resolve({ ...payload, _eventType: payloadType });
      };

      const timer = setTimeout(() => {
        this.off(payloadType, handler);
        reject(new Error(`Timeout waiting for event ${payloadType}`));
      }, timeoutMs);

      this.on(payloadType, handler);
    });
  }

  _onMessage(raw) {
    let msg, payload;
    try {
      ({ msg, payload } = this._parseFrame(raw));
    } catch (err) {
      console.error("❌ Protobuf decode error:", err.message);
      return; 
    }

    const { clientMsgId, payloadType } = msg;

    // Error response — reject the pending request
    if (payloadType === PT.ERROR_RES) {
      const pending = this.pendingRequests.get(clientMsgId);
      const errorCode = payload?.errorCode || "UNKNOWN";
      const description = payload?.description || "";
      if (errorCode === RATE_LIMIT_ERROR_CODE) {
        const backoffMs = this._rateLimitConfig().backoffMs;
        this.rateLimitBackoffUntil = Math.max(this.rateLimitBackoffUntil, Date.now() + backoffMs);
        console.warn(`⚠️  cTrader rate limit hit; pausing non-trade requests for ${(backoffMs / 1000).toFixed(0)}s.`);
      }
      if (pending) {
        this.pendingRequests.delete(clientMsgId);
        console.error(`❌ cTrader Error [${clientMsgId}]: ${errorCode} - ${description}`);
        const err = new Error(`cTrader error ${errorCode}: ${description}`);
        err.errorCode = errorCode;
        pending.reject(err);
      }
      return;
    }

    // Normal response — resolve the pending request
    if (clientMsgId && this.pendingRequests.has(clientMsgId)) {
      const pending = this.pendingRequests.get(clientMsgId);
      this.pendingRequests.delete(clientMsgId);
      pending.resolve(payload);
    }

    // Unsolicited events — trigger registered listeners
    if (this.eventListeners.has(payloadType)) {
      this.eventListeners.get(payloadType).forEach(cb => cb(payload));
    }
  }

  /**
   * Parse a cTrader binary frame (ProtoMessage)
   */
  _parseFrame(raw) {
    // raw is a Buffer (or ArrayBuffer) from ws
    const buffer = Buffer.from(raw);

    // NO 4-byte header for WebSocket
    const payloadBuffer = buffer;

    // Decode ProtoMessage
    const ProtoMessage = this.root.lookupType("ProtoMessage");
    const msg = ProtoMessage.decode(payloadBuffer);

    // Decode nested payload
    const typeName = PT_NAMES[msg.payloadType];
    let payload = {};
    if (typeName && msg.payload) {
      const InnerType = this.root.lookupType(typeName);
      payload = InnerType.toObject(InnerType.decode(msg.payload), {
        enums: String, // Convert enums to strings for convenience
        longs: Number, // Convert longs to numbers
        defaults: true,
      });
    }

    return { msg, payload };
  }

  // ─── Heartbeat ─────────────────────────────────────────────────────────────

  _startHeartbeat() {
    this.heartbeatTimer = setInterval(() => {
      if (this.connected) {
        this._send(PT.HEARTBEAT, {}).catch(() => {});
      }
    }, 20_000);
  }

  /**
   * WebSocket-level ping to prevent GCP/cloud firewall idle timeout.
   * GCP drops idle TCP connections after ~10 minutes; this keeps them alive.
   */
  _startKeepalive() {
    const KEEPALIVE_MS = 4 * 60 * 1000; // every 4 minutes
    this.keepaliveTimer = setInterval(() => {
      if (this.ws && this.ws.readyState === WebSocket.OPEN) {
        this.ws.ping?.();
      }
    }, KEEPALIVE_MS);
  }

  // ─── Connection Health Monitor (Phase 4) ─────────────────────────────────

  _startHealthMonitor() {
    const timeoutMs = (config.connectionTimeoutSeconds || 10) * 1000;
    this.healthCheckTimer = setInterval(() => {
      const silenceMs = Date.now() - this.lastMessageTime;
      if (silenceMs > timeoutMs && this.connected) {
        const msg = ` EMERGENCY: No data from cTrader for ${(silenceMs / 1000).toFixed(0)}s (limit: ${config.connectionTimeoutSeconds}s)`;
        console.error(msg);
        logConnectionAlert(msg);
        if (this.onConnectionLost) {
          this.onConnectionLost(msg);
        }
      }
    }, 5_000); // Check every 5s
  }
}

function sleep(ms) {
  return new Promise((r) => setTimeout(r, ms));
}

#!/usr/bin/env node

/**
 * 5-10-20 EMA Scalping Strategy
 * M5 Execution on EURUSD — IC Markets cTrader
 */

import fs from "fs";
import { ICMarketsClient } from "./icmarkets.js";
import { config } from "./config.js";
import { detectHigherTimeframeTrend, generateNYAsianContinuationSignal, generateSignal } from "./indicators.js";
import { RiskManager } from "./risk-manager.js";

const STATE_FILE = "state.json";
const AUTO_EXECUTE = process.argv.includes("--auto-execute");
const PAIRS = config.tradingPairs;
const GRANULARITY_MS = {
  M1: 60_000,
  M2: 2 * 60_000,
  M3: 3 * 60_000,
  M4: 4 * 60_000,
  M5: 5 * 60_000,
  M10: 10 * 60_000,
  M15: 15 * 60_000,
  M30: 30 * 60_000,
  H1: 60 * 60_000,
  H4: 4 * 60 * 60_000,
  D1: 24 * 60 * 60_000,
};

const icmarkets = new ICMarketsClient();
const riskManager = new RiskManager(config);
const pairState = new Map();

function getState(pair) {
  if (!pairState.has(pair)) {
    pairState.set(pair, {
      candleCache: [],
      higherTimeframeCandleCache: [],
      activeTrades: [],
      pendingOrders: [],
      sessionTradeCounts: new Map(),
      cooldownCandlesRemaining: 0,
      lastCandleTime: null,
      lastLogTime: 0,
    });
  }
  return pairState.get(pair);
}

async function run() {
  console.log(`\n${"═".repeat(60)}`);
  console.log(`   EURUSD M5 BOT — ${config.strategy.mode.toUpperCase()}`);
  console.log(`  Mode: ${AUTO_EXECUTE ? " AUTO-EXECUTE" : " MONITOR ONLY"}`);
  console.log(`  Session: ${config.sessionWindowMode} | Risk: ${config.risk.riskPerTradePercent}% per trade`);
  console.log(`${"═".repeat(60)}\n`);

  console.log(`   Connecting to cTrader (${config.ctraderEnv})...`);
  await icmarkets.connect();
  console.log(`  ✅ Connected.`);

  await new Promise(r => setTimeout(r, 1000));

  console.log(`   Authenticating trading account...`);
  await icmarkets.authenticate();
  console.log(`  ✅ Authenticated.`);

  for (const pair of PAIRS) {
    console.log(`   Reconciling account state for ${pair}...`);
    await reconcileAccount(pair);
    console.log(`   Subscribing to live ticks for ${pair}...`);
    await icmarkets.subscribeTicks(pair);
  }

  icmarkets.on(2126, (payload) => handleExecutionEvent(payload));

  console.log(`  ⏱️ Poll loop started (${config.pollIntervalSeconds}s interval).`);
  await tick();
  setInterval(tick, config.pollIntervalSeconds * 1000);
}

async function tick() {
  const timestamp = new Date().toLocaleTimeString();
  const now = new Date();

  const day = now.getUTCDay();
  const activeWindow = getActiveSessionWindowUTC(now);
  if (day === 0 || day === 6 || !activeWindow) {
    const utcHour = `${now.getUTCHours()}`.padStart(2, "0");
    const utcMin = `${now.getUTCMinutes()}`.padStart(2, "0");
    process.stdout.write(`[${timestamp}]  Outside trading windows (${utcHour}:${utcMin} UTC)\r`);
    return;
  }

  for (const pair of PAIRS) {
    await tickPair(pair, timestamp).catch(err => console.error(`  ❌ ${pair} error:`, err.message));
  }
}

async function tickPair(pair, timestamp) {
  const state = getState(pair);
  const now   = Date.now();
  const isJPY = pair.includes("JPY");

  // 1. Refresh candles every poll to avoid stale trend/signal state.
  try {
    const candleCount = config.strategy.mode === "ny_asian_continuation"
      ? (config.strategy.nyAsianContinuation?.lookbackCandles ?? 220)
      : 100;
    const latestCandles = await getLiveMidCandles(pair, config.granularity, candleCount + 2);
    const closedCandles = onlyClosedCandles(latestCandles, config.granularity, now);
    if (closedCandles.length > 0) {
      state.candleCache = closedCandles.slice(-candleCount);
    }
  } catch (err) {
    if (!state.candleCache.length) {
      throw err;
    }
  }

  const htfConfig = config.strategy.higherTimeframeTrend ?? {};
  let higherTimeframe = { trend: 'neutral', ema: null, close: null, reason: 'Higher-timeframe filter disabled' };
  if (htfConfig.enabled) {
    try {
      const htfGranularity = htfConfig.granularity || config.higherTimeframe || "H1";
      const htfCandleCount = htfConfig.lookbackCandles || 250;
      const htfCandles = await getLiveMidCandles(
        pair,
        htfGranularity,
        htfCandleCount + 2,
      );
      const closedHtfCandles = onlyClosedCandles(htfCandles, htfGranularity, now);
      if (closedHtfCandles.length > 0) {
        state.higherTimeframeCandleCache = closedHtfCandles.slice(-htfCandleCount);
      }
    } catch (err) {
      if (!state.higherTimeframeCandleCache.length) {
        console.error(`  ⚠️  ${pair} HTF data unavailable: ${err.message}`);
      }
    }

    higherTimeframe = detectHigherTimeframeTrend(state.higherTimeframeCandleCache, {
      emaPeriod: htfConfig.emaPeriod || 200,
      requireSlope: htfConfig.requireSlope ?? true,
    });
  }

  if (state.candleCache.length < 22) return;

  const currentCandleTime = state.candleCache[state.candleCache.length - 1]?.time ?? null;
  if (currentCandleTime && currentCandleTime !== state.lastCandleTime) {
    if (state.lastCandleTime && state.cooldownCandlesRemaining > 0) {
      state.cooldownCandlesRemaining -= 1;
    }
    for (const trade of state.activeTrades) {
      trade.ageBars = (trade.ageBars ?? 0) + 1;
    }
    state.lastCandleTime = currentCandleTime;
  }

  if (state.cooldownCandlesRemaining > 0) return;

  await manageActiveTradeTimeExits(pair, state);
  await processPendingOrders(pair, state);
  if (state.activeTrades.length >= config.maxTradesPerPair) return;
  if (!hasAvailableTradeSlot()) return;

  // 2. Generate signal
  const activeWindow = getActiveSessionWindowUTC(new Date());
  const signal = generateStrategySignal(state, higherTimeframe, activeWindow, isJPY);

  // Log status every minute
  if (now - (state.lastLogTime || 0) > 60000) {
    console.log(
      `[${timestamp}] ${pair} | Trend: ${signal.trend.toUpperCase()} | ` +
      `HTF: ${higherTimeframe.trend.toUpperCase()} | ` +
      `Strategy: ${config.strategy.mode} | Pending: ${state.pendingOrders.length} | ` +
      `Signal: ${signal.signal.toUpperCase()}`
    );
    if (signal.signal !== 'none') console.log(`  → ${signal.reason}`);
    state.lastLogTime = now;
  }

  if (signal.signal === 'none') return;

  // 3. Trade gate
  if (state.activeTrades.length >= config.maxTradesPerPair || state.pendingOrders.length > 0) return;
  if (!hasAvailableTradeSlot()) {
    console.log(`  ⛔ Account trade slot full: active + pending = ${getReservedTradeSlotCount()}/${getMaxTotalTrades()}`);
    return;
  }

  const action = signal.direction || signal.signal.toUpperCase(); // 'BUY' | 'SELL'

  console.log(
    `\n⚡ [${timestamp}] ${pair} ${action} | ` +
    `Entry: ${signal.entry} SL: ${signal.sl} TP: ${signal.tp} | ` +
    `Risk: ${signal.riskPips}p Reward: ${signal.rewardPips}p`
  );

  if (signal.signal === "buy_stop" || signal.signal === "sell_stop") {
    if (!AUTO_EXECUTE) return;
    if (!addPendingOrder(state, signal)) return;
    saveState();
    await processPendingOrders(pair, state);
    return;
  }

  if (!["buy", "sell"].includes(signal.signal)) {
    console.log(`  ⚠️  Unsupported live signal type "${signal.signal}" ignored.`);
    return;
  }

  if (!AUTO_EXECUTE) return;

  try {
    const gate = riskManager.canTrade();
    if (!gate.allowed) {
      console.log(`  ⛔ Risk gate blocked trade: ${gate.reason}`);
      return;
    }

    const units = riskManager.calculateVolume(pair, signal.riskPips, signal.entry);
    if (units <= 0) return;

    // Use the signal's entry price for more accurate relative SL/TP if possible,
    // though icmarkets.openPosition will fetch current market price for reliability.
    const res = await icmarkets.openPosition(pair, action, units, signal.sl, signal.tp, signal.entry);
    if (res && res.positionId) {
      state.activeTrades.push({ id: String(res.positionId), direction: action, pair, entry: signal.entry, sl: signal.sl, tp: signal.tp });
      riskManager.onTradeOpened(String(res.positionId), pair, action, signal.entry, signal.sl, signal.tp, units);
      saveState();
    }
  } catch (err) {
    console.error(`  ❌ Trade failed:`, err.message);
  }
}

// ─── Helpers ─────────────────────────────────────────────────────────────────

function generateStrategySignal(state, higherTimeframe, activeWindow, isJPY) {
  const htfConfig = config.strategy.higherTimeframeTrend ?? {};
  const htfTrend = htfConfig.enabled ? higherTimeframe.trend : null;

  if (config.strategy.mode === "ny_asian_continuation") {
    const cfg = config.strategy.nyAsianContinuation ?? {};
    if (Array.isArray(cfg.allowedSessionNames) && cfg.allowedSessionNames.length > 0 && !cfg.allowedSessionNames.includes(activeWindow?.name)) {
      return noSignal(`NY Asian continuation blocked outside allowed session (${activeWindow?.name ?? "none"})`);
    }

    const sessionKey = getSessionKey(new Date(), activeWindow);
    if ((state.sessionTradeCounts.get(sessionKey) ?? 0) >= (cfg.maxTradesPerSession ?? 1)) {
      return noSignal(`NY Asian continuation max trades reached for ${sessionKey}`);
    }

    return generateNYAsianContinuationSignal(state.candleCache, {
      ...cfg,
      asianRange: getAsianRangeFromCandles(state.candleCache, new Date(), cfg),
      higherTimeframeTrend: htfTrend,
      isJPY,
    });
  }

  return generateSignal(state.candleCache, {
    pipBuffer: config.strategy.pipBuffer,
    rrRatio:   config.strategy.rrRatio,
    minRiskPips: config.strategy.minRiskPips,
    maxRiskPips: config.strategy.maxRiskPips,
    emaSeparationMinPips: config.strategy.emaSeparationMinPips,
    higherTimeframeTrend: htfTrend,
    isJPY,
  });
}

function noSignal(reason) {
  return { signal: "none", trend: "neutral", entry: null, sl: null, tp: null, riskPips: null, rewardPips: null, reason };
}

async function getLiveMidCandles(pair, granularity, count) {
  const [bidCandles, askCandles] = await Promise.all([
    icmarkets.getCandles(pair, granularity, count, null, null, 1),
    icmarkets.getCandles(pair, granularity, count, null, null, 2),
  ]);
  return mergeBidAskCandles(bidCandles, askCandles);
}

function mergeBidAskCandles(bidCandles = [], askCandles = []) {
  if (!Array.isArray(bidCandles) || !Array.isArray(askCandles)) return [];

  const asksByTime = new Map(askCandles.map(candle => [candle.time, candle]));
  return bidCandles
    .map(bidCandle => {
      const askCandle = asksByTime.get(bidCandle.time);
      if (!askCandle) return null;

      const bid = extractPriceFields(bidCandle);
      const ask = extractPriceFields(askCandle);
      if (!bid || !ask) return null;

      return {
        time: bidCandle.time,
        complete: Boolean(bidCandle.complete && askCandle.complete),
        volume: Math.max(Number(bidCandle.volume) || 0, Number(askCandle.volume) || 0),
        bid: formatPriceFields(bid),
        ask: formatPriceFields(ask),
        mid: formatPriceFields({
          o: (bid.o + ask.o) / 2,
          h: (bid.h + ask.h) / 2,
          l: (bid.l + ask.l) / 2,
          c: (bid.c + ask.c) / 2,
        }),
      };
    })
    .filter(Boolean);
}

function extractPriceFields(candle) {
  const source = candle?.mid ?? candle?.bid ?? candle?.ask;
  if (!source) return null;
  const prices = {
    o: Number(source.o),
    h: Number(source.h),
    l: Number(source.l),
    c: Number(source.c),
  };
  return Object.values(prices).every(v => Number.isFinite(v) && v > 0) ? prices : null;
}

function formatPriceFields(prices) {
  return {
    o: prices.o.toFixed(5),
    h: prices.h.toFixed(5),
    l: prices.l.toFixed(5),
    c: prices.c.toFixed(5),
  };
}

function onlyClosedCandles(candles, granularity, nowMs = Date.now()) {
  if (!Array.isArray(candles)) return [];
  const periodMs = GRANULARITY_MS[String(granularity || "").toUpperCase()] ?? GRANULARITY_MS.M5;
  return candles.filter(candle => {
    const openMs = new Date(candle?.time).getTime();
    return Number.isFinite(openMs) && openMs + periodMs <= nowMs;
  });
}

function addPendingOrder(state, signal) {
  if (!hasAvailableTradeSlot()) {
    console.log(`  ⛔ Pending ${signal.direction} stop not armed: active + pending = ${getReservedTradeSlotCount()}/${getMaxTotalTrades()}`);
    return false;
  }

  const latest = state.candleCache.at(-1);
  const setupMs = latest?.time ? new Date(latest.time).getTime() : Date.now();
  const expiresAfterBars = signal.pendingExpiryBars ?? 3;
  const activeWindow = getActiveSessionWindowUTC(new Date());
  const sessionKey = getSessionKey(new Date(), activeWindow);

  state.pendingOrders.push({
    direction: signal.direction,
    entry: signal.entry,
    sl: signal.sl,
    tp: signal.tp,
    setupTime: signal.setupTime,
    setupCandleTime: latest?.time,
    expiresAtMs: setupMs + expiresAfterBars * 5 * 60_000,
    expiresAfterBars,
    timeExitBars: signal.timeExitBars,
    forceExitUTC: signal.forceExitUTC,
    sessionKey,
    strategy: signal.strategy,
    levelName: signal.levelName,
    levelPrice: signal.levelPrice,
    riskPips: signal.riskPips,
    rewardPips: signal.rewardPips,
    reason: signal.reason,
  });
  console.log(`   Pending ${signal.direction} stop armed @ ${signal.entry} (expires in ${expiresAfterBars} M5 bars).`);
  return true;
}

async function processPendingOrders(pair, state) {
  if (!AUTO_EXECUTE || state.pendingOrders.length === 0) return;
  const latest = normalizeLiveCandle(state.candleCache.at(-1));
  const latestTime = state.candleCache.at(-1)?.time;
  if (!latest) return;

  const kept = [];
  for (const order of state.pendingOrders) {
    if (latest.date.getTime() > order.expiresAtMs) {
      console.log(`  ⌛ Pending ${order.direction} stop expired @ ${order.entry}`);
      continue;
    }
    if (latestTime && order.setupCandleTime && latestTime === order.setupCandleTime) {
      kept.push(order);
      continue;
    }
    if (state.activeTrades.length >= config.maxTradesPerPair) {
      kept.push(order);
      continue;
    }
    if (getOpenTradeCount() >= getMaxTotalTrades()) {
      kept.push(order);
      continue;
    }

    const triggered = order.direction === "BUY" ? latest.high >= order.entry : latest.low <= order.entry;
    if (!triggered) {
      kept.push(order);
      continue;
    }

    await executeOrderSignal(pair, state, order);
  }

  state.pendingOrders = kept;
}

async function executeOrderSignal(pair, state, signal) {
  try {
    const gate = riskManager.canTrade();
    if (!gate.allowed) {
      console.log(`  ⛔ Risk gate blocked pending ${signal.direction}: ${gate.reason}`);
      return;
    }

    const units = riskManager.calculateVolume(pair, signal.riskPips, signal.entry);
    if (units <= 0) return;

    const res = await icmarkets.openPosition(pair, signal.direction, units, signal.sl, signal.tp, signal.entry);
    if (res && res.positionId) {
      state.activeTrades.push({
        id: String(res.positionId), direction: signal.direction, pair,
        entry: signal.entry, sl: signal.sl, tp: signal.tp,
        strategy: signal.strategy, sessionKey: signal.sessionKey,
        ageBars: 0, timeExitBars: signal.timeExitBars, forceExitUTC: signal.forceExitUTC,
      });
      if (signal.sessionKey) {
        state.sessionTradeCounts.set(signal.sessionKey, (state.sessionTradeCounts.get(signal.sessionKey) ?? 0) + 1);
      }
      riskManager.onTradeOpened(String(res.positionId), pair, signal.direction, signal.entry, signal.sl, signal.tp, units);
      saveState();
      console.log(`  ✅ Pending ${signal.direction} triggered and sent as market order.`);
    }
  } catch (err) {
    console.error(`  ❌ Pending order execution failed:`, err.message);
  }
}

async function manageActiveTradeTimeExits(pair, state) {
  if (!AUTO_EXECUTE || state.activeTrades.length === 0) return;
  const latest = normalizeLiveCandle(state.candleCache.at(-1));
  if (!latest) return;
  const hour = latest.date.getUTCHours() + latest.date.getUTCMinutes() / 60;

  for (const trade of state.activeTrades) {
    if (trade.closing) continue;
    const hitTimeExit = trade.timeExitBars && (trade.ageBars ?? 0) >= trade.timeExitBars;
    const hitForceExit = Number.isFinite(trade.forceExitUTC) && hour >= trade.forceExitUTC;
    if (!hitTimeExit && !hitForceExit) continue;

    trade.closing = true;
    console.log(`  ⏱️  Closing ${pair} ${trade.direction} by ${hitForceExit ? "16:00 UTC" : "time-exit"} rule.`);
    try {
      await icmarkets.closeTrade(trade.id);
    } catch (err) {
      trade.closing = false;
      console.error(`  ❌ Time-exit close failed for ${trade.id}:`, err.message);
    }
  }
}

function normalizeLiveCandle(candle) {
  if (!candle) return null;
  const m = candle.mid ?? candle.bid ?? candle.ask;
  if (!m) return null;
  const out = {
    date: new Date(candle.time),
    open: Number(m.o),
    high: Number(m.h),
    low: Number(m.l),
    close: Number(m.c),
  };
  return [out.open, out.high, out.low, out.close].every(Number.isFinite) ? out : null;
}

function getAsianRangeFromCandles(candles, dateObj, cfg = {}) {
  const day = dateObj.toISOString().slice(0, 10);
  const start = cfg.asianStartUTC ?? 0;
  const end = cfg.asianEndUTC ?? 7;
  const asian = candles
    .map(c => ({ raw: c, norm: normalizeLiveCandle(c) }))
    .filter(({ raw, norm }) => {
      if (!norm || raw.time.slice(0, 10) !== day) return false;
      const h = norm.date.getUTCHours() + norm.date.getUTCMinutes() / 60;
      return h >= start && h < end;
    })
    .map(x => x.norm);

  if (asian.length < 12) return null;
  return {
    name: "asian_range",
    high: Math.max(...asian.map(c => c.high)),
    low: Math.min(...asian.map(c => c.low)),
    start,
    end,
  };
}

function handleExecutionEvent(payload) {
  if (payload.executionType === "DEAL_FILLED" || payload.executionType === 4) {
    const deal = payload.deal;
    if (deal && deal.closePositionDetail) {
      const positionId = String(deal.positionId);
      let matchedTrade = null;
      console.log(`    Position ${positionId} closed.`);
      for (const [, state] of pairState) {
        const found = state.activeTrades.find(t => t.id === positionId);
        if (found) matchedTrade = found;
        state.activeTrades = state.activeTrades.filter(t => t.id !== positionId);
      }
      const pnlKES = realizedPnlKES(deal);
      if (Number.isFinite(pnlKES)) {
        riskManager.onTradeClosed(positionId, pnlKES);
      }
      riskManager.syncOpenTradeCount(getOpenTradeCount());

      if (matchedTrade && config.strategy.cooldownCandlesAfterLoss > 0) {
        let exitPrice = Number(deal.executionPrice ?? 0);
        if (exitPrice > 1000) exitPrice = exitPrice / 100000;
        const pipSize = matchedTrade.pair?.includes("JPY") ? 0.01 : 0.0001;
        const epsilon = pipSize * 2;
        if (Math.abs(exitPrice - matchedTrade.sl) <= epsilon) {
          const state = getState(matchedTrade.pair);
          state.cooldownCandlesRemaining = Math.max(state.cooldownCandlesRemaining, config.strategy.cooldownCandlesAfterLoss);
        }
      }

      saveState();
    }
  }
}

function realizedPnlKES(deal) {
  const detail = deal?.closePositionDetail;
  if (!detail) return null;
  const moneyDigits = Number(detail.moneyDigits ?? deal.moneyDigits ?? 2);
  const divisor = 10 ** moneyDigits;
  const gross = Number(detail.grossProfit ?? 0);
  const swap = Number(detail.swap ?? 0);
  const commission = Number(detail.commission ?? 0);
  const conversionFee = Number(detail.pnlConversionFee ?? 0);
  const pnlDepositCurrency = (gross + swap + commission + conversionFee) / divisor;
  return pnlDepositCurrency * (config.risk.usdKesRate ?? 129.0);
}

async function reconcileAccount(pair) {
  const state = getState(pair);
  try {
    const positions = await icmarkets.reconcile();
    const symbolId = icmarkets._resolveSymbolId(pair);
    state.activeTrades = positions
      .filter(p => p.tradeData && String(p.tradeData.symbolId) === String(symbolId))
      .map(p => ({ id: String(p.positionId), direction: p.tradeData.tradeSide, pair }));
    riskManager.syncOpenTradeCount(getOpenTradeCount());
    saveState();
  } catch (err) {}
}

function getOpenTradeCount() {
  let count = 0;
  for (const [, state] of pairState) count += state.activeTrades.length;
  return count;
}

function getPendingOrderCount() {
  let count = 0;
  for (const [, state] of pairState) count += state.pendingOrders.length;
  return count;
}

function getReservedTradeSlotCount() {
  return getOpenTradeCount() + getPendingOrderCount();
}

function getMaxTotalTrades() {
  const configured = Number(config.maxTotalTrades);
  return Number.isFinite(configured) && configured > 0 ? configured : Infinity;
}

function hasAvailableTradeSlot() {
  return getReservedTradeSlotCount() < getMaxTotalTrades();
}

function saveState() {
  const allTrades = [];
  for (const [, state] of pairState) allTrades.push(...state.activeTrades);
  fs.writeFileSync(STATE_FILE, JSON.stringify({ activeTrades: allTrades }, null, 2));
}

function getSessionKey(dateObj, activeWindow) {
  return `${dateObj.toISOString().slice(0, 10)}:${activeWindow?.name ?? "unknown"}`;
}

function getActiveSessionWindowUTC(now) {
  const windows = config.sessionWindowsUTC;
  if (!Array.isArray(windows) || windows.length === 0) {
    const h = now.getUTCHours() + (now.getUTCMinutes() / 60);
    return h >= config.sessionStartUTC && h < config.sessionEndUTC ? { name: "legacy" } : null;
  }

  const h = now.getUTCHours() + (now.getUTCMinutes() / 60);
  return windows.find(w => h >= w.start && h < w.end) || null;
}

run().catch(console.error);

#!/usr/bin/env node

/**
 * 5-10-20 EMA Scalping Strategy
 * M5 Execution on EURUSD — IC Markets cTrader
 */

import fs from "fs";
import { ICMarketsClient } from "./icmarkets.js";
import { config } from "./config.js";
import { detectHigherTimeframeTrend, generateNYAsianContinuationSignal, generateSignal } from "./indicators.js";
import { RiskManager } from "./risk-manager.js";

const STATE_FILE = "state.json";
const AUTO_EXECUTE = process.argv.includes("--auto-execute");
const PAIRS = config.tradingPairs;
const GRANULARITY_MS = {
  M1: 60_000,
  M2: 2 * 60_000,
  M3: 3 * 60_000,
  M4: 4 * 60_000,
  M5: 5 * 60_000,
  M10: 10 * 60_000,
  M15: 15 * 60_000,
  M30: 30 * 60_000,
  H1: 60 * 60_000,
  H4: 4 * 60 * 60_000,
  D1: 24 * 60 * 60_000,
};

const icmarkets = new ICMarketsClient();
const riskManager = new RiskManager(config);
const pairState = new Map();

function getState(pair) {
  if (!pairState.has(pair)) {
    pairState.set(pair, {
      candleCache: [],
      higherTimeframeCandleCache: [],
      activeTrades: [],
      pendingOrders: [],
      sessionTradeCounts: new Map(),
      cooldownCandlesRemaining: 0,
      lastCandleTime: null,
      lastEntryCandleFetchAt: 0,
      lastHigherTimeframeCandleFetchAt: 0,
      lastLogTime: 0,
    });
  }
  return pairState.get(pair);
}

async function run() {
  console.log(`\n${"═".repeat(60)}`);
  console.log(`   EURUSD M5 BOT — ${config.strategy.mode.toUpperCase()}`);
  console.log(`  Mode: ${AUTO_EXECUTE ? " AUTO-EXECUTE" : " MONITOR ONLY"}`);
  console.log(`  Session: ${config.sessionWindowMode} | Risk: ${config.risk.riskPerTradePercent}% per trade`);
  console.log(`${"═".repeat(60)}\n`);

  console.log(`   Connecting to cTrader (${config.ctraderEnv})...`);
  await icmarkets.connect();
  console.log(`  ✅ Connected.`);

  await new Promise(r => setTimeout(r, 1000));

  console.log(`   Authenticating trading account...`);
  await icmarkets.authenticate();
  console.log(`  ✅ Authenticated.`);

  for (const pair of PAIRS) {
    console.log(`   Reconciling account state for ${pair}...`);
    await reconcileAccount(pair);
    console.log(`   Subscribing to live ticks for ${pair}...`);
    await icmarkets.subscribeTicks(pair);
  }

  icmarkets.on(2126, (payload) => handleExecutionEvent(payload));

  console.log(`  ⏱️ Poll loop started (${config.pollIntervalSeconds}s interval).`);
  await tick();
  setInterval(tick, config.pollIntervalSeconds * 1000);
}

async function tick() {
  const timestamp = new Date().toLocaleTimeString();
  const now = new Date();

  const day = now.getUTCDay();
  const activeWindow = getActiveSessionWindowUTC(now);
  if (day === 0 || day === 6 || !activeWindow) {
    const utcHour = `${now.getUTCHours()}`.padStart(2, "0");
    const utcMin = `${now.getUTCMinutes()}`.padStart(2, "0");
    process.stdout.write(`[${timestamp}]  Outside trading windows (${utcHour}:${utcMin} UTC)\r`);
    return;
  }

  for (const pair of PAIRS) {
    await tickPair(pair, timestamp).catch(err => console.error(`  ❌ ${pair} error:`, err.message));
  }
}

async function tickPair(pair, timestamp) {
  const state = getState(pair);
  const now   = Date.now();
  const isJPY = pair.includes("JPY");

  // 1. Refresh candles only when a new closed candle can exist.
  const candleCount = config.strategy.mode === "ny_asian_continuation"
    ? (config.strategy.nyAsianContinuation?.lookbackCandles ?? 220)
    : 100;
  if (shouldRefreshClosedCandles(state.candleCache, config.granularity, now, state.lastEntryCandleFetchAt)) {
    state.lastEntryCandleFetchAt = now;
    try {
      const latestCandles = await getLiveMidCandles(pair, config.granularity, candleCount + 2);
      const closedCandles = onlyClosedCandles(latestCandles, config.granularity, now);
      if (closedCandles.length > 0) {
        state.candleCache = closedCandles.slice(-candleCount);
      }
    } catch (err) {
      if (!state.candleCache.length) {
        throw err;
      }
    }
  }

  const htfConfig = config.strategy.higherTimeframeTrend ?? {};
  let higherTimeframe = { trend: 'neutral', ema: null, close: null, reason: 'Higher-timeframe filter disabled' };
  if (htfConfig.enabled) {
    try {
      const htfGranularity = htfConfig.granularity || config.higherTimeframe || "H1";
      const htfCandleCount = htfConfig.lookbackCandles || 250;
      if (shouldRefreshClosedCandles(state.higherTimeframeCandleCache, htfGranularity, now, state.lastHigherTimeframeCandleFetchAt)) {
        state.lastHigherTimeframeCandleFetchAt = now;
        const htfCandles = await getLiveMidCandles(
          pair,
          htfGranularity,
          htfCandleCount + 2,
        );
        const closedHtfCandles = onlyClosedCandles(htfCandles, htfGranularity, now);
        if (closedHtfCandles.length > 0) {
          state.higherTimeframeCandleCache = closedHtfCandles.slice(-htfCandleCount);
        }
      }
    } catch (err) {
      if (!state.higherTimeframeCandleCache.length) {
        console.error(`  ⚠️  ${pair} HTF data unavailable: ${err.message}`);
      }
    }

    higherTimeframe = detectHigherTimeframeTrend(state.higherTimeframeCandleCache, {
      emaPeriod: htfConfig.emaPeriod || 200,
      requireSlope: htfConfig.requireSlope ?? true,
    });
  }

  if (state.candleCache.length < 22) return;

  const currentCandleTime = state.candleCache[state.candleCache.length - 1]?.time ?? null;
  if (currentCandleTime && currentCandleTime !== state.lastCandleTime) {
    if (state.lastCandleTime && state.cooldownCandlesRemaining > 0) {
      state.cooldownCandlesRemaining -= 1;
    }
    for (const trade of state.activeTrades) {
      trade.ageBars = (trade.ageBars ?? 0) + 1;
    }
    state.lastCandleTime = currentCandleTime;
  }

  if (state.cooldownCandlesRemaining > 0) return;

  await manageActiveTradeTimeExits(pair, state);
  await processPendingOrders(pair, state);
  if (state.activeTrades.length >= config.maxTradesPerPair) return;
  if (!hasAvailableTradeSlot()) return;

  // 2. Generate signal
  const activeWindow = getActiveSessionWindowUTC(new Date());
  const signal = generateStrategySignal(state, higherTimeframe, activeWindow, isJPY);

  // Log status every minute
  if (now - (state.lastLogTime || 0) > 60000) {
    console.log(
      `[${timestamp}] ${pair} | Trend: ${signal.trend.toUpperCase()} | ` +
      `HTF: ${higherTimeframe.trend.toUpperCase()} | ` +
      `Strategy: ${config.strategy.mode} | Pending: ${state.pendingOrders.length} | ` +
      `Signal: ${signal.signal.toUpperCase()}`
    );
    if (signal.signal !== 'none') console.log(`  → ${signal.reason}`);
    state.lastLogTime = now;
  }

  if (signal.signal === 'none') return;

  // 3. Trade gate
  if (state.activeTrades.length >= config.maxTradesPerPair || state.pendingOrders.length > 0) return;
  if (!hasAvailableTradeSlot()) {
    console.log(`  ⛔ Account trade slot full: active + pending = ${getReservedTradeSlotCount()}/${getMaxTotalTrades()}`);
    return;
  }

  const action = signal.direction || signal.signal.toUpperCase(); // 'BUY' | 'SELL'

  console.log(
    `\n⚡ [${timestamp}] ${pair} ${action} | ` +
    `Entry: ${signal.entry} SL: ${signal.sl} TP: ${signal.tp} | ` +
    `Risk: ${signal.riskPips}p Reward: ${signal.rewardPips}p`
  );

  if (signal.signal === "buy_stop" || signal.signal === "sell_stop") {
    if (!AUTO_EXECUTE) return;
    if (!addPendingOrder(state, signal)) return;
    saveState();
    await processPendingOrders(pair, state);
    return;
  }

  if (!["buy", "sell"].includes(signal.signal)) {
    console.log(`  ⚠️  Unsupported live signal type "${signal.signal}" ignored.`);
    return;
  }

  if (!AUTO_EXECUTE) return;

  try {
    const gate = riskManager.canTrade();
    if (!gate.allowed) {
      console.log(`  ⛔ Risk gate blocked trade: ${gate.reason}`);
      return;
    }

    const units = riskManager.calculateVolume(pair, signal.riskPips, signal.entry);
    if (units <= 0) return;

    // Use the signal's entry price for more accurate relative SL/TP if possible,
    // though icmarkets.openPosition will fetch current market price for reliability.
    const res = await icmarkets.openPosition(pair, action, units, signal.sl, signal.tp, signal.entry);
    if (res && res.positionId) {
      state.activeTrades.push({ id: String(res.positionId), direction: action, pair, entry: signal.entry, sl: signal.sl, tp: signal.tp });
      riskManager.onTradeOpened(String(res.positionId), pair, action, signal.entry, signal.sl, signal.tp, units);
      saveState();
    }
  } catch (err) {
    console.error(`  ❌ Trade failed:`, err.message);
  }
}

// ─── Helpers ─────────────────────────────────────────────────────────────────

function generateStrategySignal(state, higherTimeframe, activeWindow, isJPY) {
  const htfConfig = config.strategy.higherTimeframeTrend ?? {};
  const htfTrend = htfConfig.enabled ? higherTimeframe.trend : null;

  if (config.strategy.mode === "ny_asian_continuation") {
    const cfg = config.strategy.nyAsianContinuation ?? {};
    if (Array.isArray(cfg.allowedSessionNames) && cfg.allowedSessionNames.length > 0 && !cfg.allowedSessionNames.includes(activeWindow?.name)) {
      return noSignal(`NY Asian continuation blocked outside allowed session (${activeWindow?.name ?? "none"})`);
    }

    const sessionKey = getSessionKey(new Date(), activeWindow);
    if ((state.sessionTradeCounts.get(sessionKey) ?? 0) >= (cfg.maxTradesPerSession ?? 1)) {
      return noSignal(`NY Asian continuation max trades reached for ${sessionKey}`);
    }

    return generateNYAsianContinuationSignal(state.candleCache, {
      ...cfg,
      asianRange: getAsianRangeFromCandles(state.candleCache, new Date(), cfg),
      higherTimeframeTrend: htfTrend,
      isJPY,
    });
  }

  return generateSignal(state.candleCache, {
    pipBuffer: config.strategy.pipBuffer,
    rrRatio:   config.strategy.rrRatio,
    minRiskPips: config.strategy.minRiskPips,
    maxRiskPips: config.strategy.maxRiskPips,
    emaSeparationMinPips: config.strategy.emaSeparationMinPips,
    higherTimeframeTrend: htfTrend,
    isJPY,
  });
}

function noSignal(reason) {
  return { signal: "none", trend: "neutral", entry: null, sl: null, tp: null, riskPips: null, rewardPips: null, reason };
}

async function getLiveMidCandles(pair, granularity, count) {
  const [bidCandles, askCandles] = await Promise.all([
    icmarkets.getCandles(pair, granularity, count, null, null, 1),
    icmarkets.getCandles(pair, granularity, count, null, null, 2),
  ]);
  return mergeBidAskCandles(bidCandles, askCandles);
}

function mergeBidAskCandles(bidCandles = [], askCandles = []) {
  if (!Array.isArray(bidCandles) || !Array.isArray(askCandles)) return [];

  const asksByTime = new Map(askCandles.map(candle => [candle.time, candle]));
  return bidCandles
    .map(bidCandle => {
      const askCandle = asksByTime.get(bidCandle.time);
      if (!askCandle) return null;

      const bid = extractPriceFields(bidCandle);
      const ask = extractPriceFields(askCandle);
      if (!bid || !ask) return null;

      return {
        time: bidCandle.time,
        complete: Boolean(bidCandle.complete && askCandle.complete),
        volume: Math.max(Number(bidCandle.volume) || 0, Number(askCandle.volume) || 0),
        bid: formatPriceFields(bid),
        ask: formatPriceFields(ask),
        mid: formatPriceFields({
          o: (bid.o + ask.o) / 2,
          h: (bid.h + ask.h) / 2,
          l: (bid.l + ask.l) / 2,
          c: (bid.c + ask.c) / 2,
        }),
      };
    })
    .filter(Boolean);
}

function extractPriceFields(candle) {
  const source = candle?.mid ?? candle?.bid ?? candle?.ask;
  if (!source) return null;
  const prices = {
    o: Number(source.o),
    h: Number(source.h),
    l: Number(source.l),
    c: Number(source.c),
  };
  return Object.values(prices).every(v => Number.isFinite(v) && v > 0) ? prices : null;
}

function formatPriceFields(prices) {
  return {
    o: prices.o.toFixed(5),
    h: prices.h.toFixed(5),
    l: prices.l.toFixed(5),
    c: prices.c.toFixed(5),
  };
}

function onlyClosedCandles(candles, granularity, nowMs = Date.now()) {
  if (!Array.isArray(candles)) return [];
  const periodMs = GRANULARITY_MS[String(granularity || "").toUpperCase()] ?? GRANULARITY_MS.M5;
  return candles.filter(candle => {
    const openMs = new Date(candle?.time).getTime();
    return Number.isFinite(openMs) && openMs + periodMs <= nowMs;
  });
}

function shouldRefreshClosedCandles(cache, granularity, nowMs = Date.now(), lastFetchMs = 0) {
  const periodMs = GRANULARITY_MS[String(granularity || "").toUpperCase()] ?? GRANULARITY_MS.M5;
  const retryMs = Math.min(30_000, Math.max(10_000, Math.floor(periodMs / 4)));

  if (!Array.isArray(cache) || cache.length === 0) {
    return nowMs - (lastFetchMs || 0) >= retryMs;
  }

  const lastClosedOpenMs = new Date(cache.at(-1)?.time).getTime();
  if (!Number.isFinite(lastClosedOpenMs)) {
    return nowMs - (lastFetchMs || 0) >= retryMs;
  }

  // If the latest cached closed candle opened at T, the next closed candle is
  // not available until T + 2 periods (plus a small broker timestamp grace).
  return nowMs >= lastClosedOpenMs + (periodMs * 2) + 2_000;
}

function addPendingOrder(state, signal) {
  if (!hasAvailableTradeSlot()) {
    console.log(`  ⛔ Pending ${signal.direction} stop not armed: active + pending = ${getReservedTradeSlotCount()}/${getMaxTotalTrades()}`);
    return false;
  }

  const latest = state.candleCache.at(-1);
  const setupMs = latest?.time ? new Date(latest.time).getTime() : Date.now();
  const expiresAfterBars = signal.pendingExpiryBars ?? 3;
  const activeWindow = getActiveSessionWindowUTC(new Date());
  const sessionKey = getSessionKey(new Date(), activeWindow);

  state.pendingOrders.push({
    direction: signal.direction,
    entry: signal.entry,
    sl: signal.sl,
    tp: signal.tp,
    setupTime: signal.setupTime,
    setupCandleTime: latest?.time,
    expiresAtMs: setupMs + expiresAfterBars * 5 * 60_000,
    expiresAfterBars,
    timeExitBars: signal.timeExitBars,
    forceExitUTC: signal.forceExitUTC,
    sessionKey,
    strategy: signal.strategy,
    levelName: signal.levelName,
    levelPrice: signal.levelPrice,
    riskPips: signal.riskPips,
    rewardPips: signal.rewardPips,
    reason: signal.reason,
  });
  console.log(`   Pending ${signal.direction} stop armed @ ${signal.entry} (expires in ${expiresAfterBars} M5 bars).`);
  return true;
}

async function processPendingOrders(pair, state) {
  if (!AUTO_EXECUTE || state.pendingOrders.length === 0) return;
  const latest = normalizeLiveCandle(state.candleCache.at(-1));
  const latestTime = state.candleCache.at(-1)?.time;
  if (!latest) return;

  const kept = [];
  for (const order of state.pendingOrders) {
    if (latest.date.getTime() > order.expiresAtMs) {
      console.log(`  ⌛ Pending ${order.direction} stop expired @ ${order.entry}`);
      continue;
    }
    if (latestTime && order.setupCandleTime && latestTime === order.setupCandleTime) {
      kept.push(order);
      continue;
    }
    if (state.activeTrades.length >= config.maxTradesPerPair) {
      kept.push(order);
      continue;
    }
    if (getOpenTradeCount() >= getMaxTotalTrades()) {
      kept.push(order);
      continue;
    }

    const triggered = order.direction === "BUY" ? latest.high >= order.entry : latest.low <= order.entry;
    if (!triggered) {
      kept.push(order);
      continue;
    }

    await executeOrderSignal(pair, state, order);
  }

  state.pendingOrders = kept;
}

async function executeOrderSignal(pair, state, signal) {
  try {
    const gate = riskManager.canTrade();
    if (!gate.allowed) {
      console.log(`  ⛔ Risk gate blocked pending ${signal.direction}: ${gate.reason}`);
      return;
    }

    const units = riskManager.calculateVolume(pair, signal.riskPips, signal.entry);
    if (units <= 0) return;

    const res = await icmarkets.openPosition(pair, signal.direction, units, signal.sl, signal.tp, signal.entry);
    if (res && res.positionId) {
      state.activeTrades.push({
        id: String(res.positionId), direction: signal.direction, pair,
        entry: signal.entry, sl: signal.sl, tp: signal.tp,
        strategy: signal.strategy, sessionKey: signal.sessionKey,
        ageBars: 0, timeExitBars: signal.timeExitBars, forceExitUTC: signal.forceExitUTC,
      });
      if (signal.sessionKey) {
        state.sessionTradeCounts.set(signal.sessionKey, (state.sessionTradeCounts.get(signal.sessionKey) ?? 0) + 1);
      }
      riskManager.onTradeOpened(String(res.positionId), pair, signal.direction, signal.entry, signal.sl, signal.tp, units);
      saveState();
      console.log(`  ✅ Pending ${signal.direction} triggered and sent as market order.`);
    }
  } catch (err) {
    console.error(`  ❌ Pending order execution failed:`, err.message);
  }
}

async function manageActiveTradeTimeExits(pair, state) {
  if (!AUTO_EXECUTE || state.activeTrades.length === 0) return;
  const latest = normalizeLiveCandle(state.candleCache.at(-1));
  if (!latest) return;
  const hour = latest.date.getUTCHours() + latest.date.getUTCMinutes() / 60;

  for (const trade of state.activeTrades) {
    if (trade.closing) continue;
    const hitTimeExit = trade.timeExitBars && (trade.ageBars ?? 0) >= trade.timeExitBars;
    const hitForceExit = Number.isFinite(trade.forceExitUTC) && hour >= trade.forceExitUTC;
    if (!hitTimeExit && !hitForceExit) continue;

    trade.closing = true;
    console.log(`  ⏱️  Closing ${pair} ${trade.direction} by ${hitForceExit ? "16:00 UTC" : "time-exit"} rule.`);
    try {
      await icmarkets.closeTrade(trade.id);
    } catch (err) {
      trade.closing = false;
      console.error(`  ❌ Time-exit close failed for ${trade.id}:`, err.message);
    }
  }
}

function normalizeLiveCandle(candle) {
  if (!candle) return null;
  const m = candle.mid ?? candle.bid ?? candle.ask;
  if (!m) return null;
  const out = {
    date: new Date(candle.time),
    open: Number(m.o),
    high: Number(m.h),
    low: Number(m.l),
    close: Number(m.c),
  };
  return [out.open, out.high, out.low, out.close].every(Number.isFinite) ? out : null;
}

function getAsianRangeFromCandles(candles, dateObj, cfg = {}) {
  const day = dateObj.toISOString().slice(0, 10);
  const start = cfg.asianStartUTC ?? 0;
  const end = cfg.asianEndUTC ?? 7;
  const asian = candles
    .map(c => ({ raw: c, norm: normalizeLiveCandle(c) }))
    .filter(({ raw, norm }) => {
      if (!norm || raw.time.slice(0, 10) !== day) return false;
      const h = norm.date.getUTCHours() + norm.date.getUTCMinutes() / 60;
      return h >= start && h < end;
    })
    .map(x => x.norm);

  if (asian.length < 12) return null;
  return {
    name: "asian_range",
    high: Math.max(...asian.map(c => c.high)),
    low: Math.min(...asian.map(c => c.low)),
    start,
    end,
  };
}

function handleExecutionEvent(payload) {
  if (payload.executionType === "DEAL_FILLED" || payload.executionType === 4) {
    const deal = payload.deal;
    if (deal && deal.closePositionDetail) {
      const positionId = String(deal.positionId);
      let matchedTrade = null;
      console.log(`    Position ${positionId} closed.`);
      for (const [, state] of pairState) {
        const found = state.activeTrades.find(t => t.id === positionId);
        if (found) matchedTrade = found;
        state.activeTrades = state.activeTrades.filter(t => t.id !== positionId);
      }
      const pnlKES = realizedPnlKES(deal);
      if (Number.isFinite(pnlKES)) {
        riskManager.onTradeClosed(positionId, pnlKES);
      }
      riskManager.syncOpenTradeCount(getOpenTradeCount());

      if (matchedTrade && config.strategy.cooldownCandlesAfterLoss > 0) {
        let exitPrice = Number(deal.executionPrice ?? 0);
        if (exitPrice > 1000) exitPrice = exitPrice / 100000;
        const pipSize = matchedTrade.pair?.includes("JPY") ? 0.01 : 0.0001;
        const epsilon = pipSize * 2;
        if (Math.abs(exitPrice - matchedTrade.sl) <= epsilon) {
          const state = getState(matchedTrade.pair);
          state.cooldownCandlesRemaining = Math.max(state.cooldownCandlesRemaining, config.strategy.cooldownCandlesAfterLoss);
        }
      }

      saveState();
    }
  }
}

function realizedPnlKES(deal) {
  const detail = deal?.closePositionDetail;
  if (!detail) return null;
  const moneyDigits = Number(detail.moneyDigits ?? deal.moneyDigits ?? 2);
  const divisor = 10 ** moneyDigits;
  const gross = Number(detail.grossProfit ?? 0);
  const swap = Number(detail.swap ?? 0);
  const commission = Number(detail.commission ?? 0);
  const conversionFee = Number(detail.pnlConversionFee ?? 0);
  const pnlDepositCurrency = (gross + swap + commission + conversionFee) / divisor;
  return pnlDepositCurrency * (config.risk.usdKesRate ?? 129.0);
}

async function reconcileAccount(pair) {
  const state = getState(pair);
  try {
    const positions = await icmarkets.reconcile();
    const symbolId = icmarkets._resolveSymbolId(pair);
    state.activeTrades = positions
      .filter(p => p.tradeData && String(p.tradeData.symbolId) === String(symbolId))
      .map(p => ({ id: String(p.positionId), direction: p.tradeData.tradeSide, pair }));
    riskManager.syncOpenTradeCount(getOpenTradeCount());
    saveState();
  } catch (err) {}
}

function getOpenTradeCount() {
  let count = 0;
  for (const [, state] of pairState) count += state.activeTrades.length;
  return count;
}

function getPendingOrderCount() {
  let count = 0;
  for (const [, state] of pairState) count += state.pendingOrders.length;
  return count;
}

function getReservedTradeSlotCount() {
  return getOpenTradeCount() + getPendingOrderCount();
}

function getMaxTotalTrades() {
  const configured = Number(config.maxTotalTrades);
  return Number.isFinite(configured) && configured > 0 ? configured : Infinity;
}

function hasAvailableTradeSlot() {
  return getReservedTradeSlotCount() < getMaxTotalTrades();
}

function saveState() {
  const allTrades = [];
  for (const [, state] of pairState) allTrades.push(...state.activeTrades);
  fs.writeFileSync(STATE_FILE, JSON.stringify({ activeTrades: allTrades }, null, 2));
}

function getSessionKey(dateObj, activeWindow) {
  return `${dateObj.toISOString().slice(0, 10)}:${activeWindow?.name ?? "unknown"}`;
}

function getActiveSessionWindowUTC(now) {
  const windows = config.sessionWindowsUTC;
  if (!Array.isArray(windows) || windows.length === 0) {
    const h = now.getUTCHours() + (now.getUTCMinutes() / 60);
    return h >= config.sessionStartUTC && h < config.sessionEndUTC ? { name: "legacy" } : null;
  }

  const h = now.getUTCHours() + (now.getUTCMinutes() / 60);
  return windows.find(w => h >= w.start && h < w.end) || null;
}

run().catch(console.error);
